-- Data for agent_events (1741 rows)
INSERT INTO `agent_events` (`id`, `agent_id`, `event_type`, `node_id`, `message`, `detail`, `created_at`) VALUES
(5663, 8, 'system', 'tp-zhongzheng', '✨ 旅人獲得了名字：凜冬月。命運的齒輪開始轉動……', '{"name":"凜冬月","type":"naming"}', 1774376023665),
(5664, 8, 'gather', 'tp-zhongzheng', '凜冬月 發現了一叢 mat-earth-002，小心翼翼地採摘。', '{"itemId":"mat-earth-002"}', 1774376055997),
(5665, 8, 'move', 'tp-zhongzheng', '🗺️ 凜冬月 啟程前往 林口台地！（消耗 2 點體力）', '{"targetNodeId":"nb-linkou","targetNodeName":"林口台地","type":"teleport"}', 1774376066080),
(5666, 8, 'move', 'nb-linkou', '凜冬月 抵達 林口台地，海拔較高的台地，金靈能量在強勁海風中流動，林口長庚醫院如城堡般矗立。', '{"nodeId":"nb-linkou"}', 1774376075527),
(5667, 8, 'rest', 'nb-linkou', '【注靈成功】凜冬月在「林口台地」感懟天地金氣，成功截取 0.15 點金五行之力！（金：4.0 → 4.2）', '{"element":"metal","gain":0.15,"newVal":4.15,"type":"infuse_success"}', 1774376081276),
(5668, 8, 'rest', 'nb-linkou', '【注靈成功】凜冬月在「林口台地」感懟天地金氣，成功截取 0.14 點金五行之力！（金：4.0 → 4.1）', '{"element":"metal","gain":0.14,"newVal":4.14,"type":"infuse_success"}', 1774376085546),
(5669, 8, 'rest', 'nb-linkou', '【注靈成功】凜冬月在「林口台地」感懟天地金氣，成功截取 0.18 點金五行之力！（金：4.0 → 4.2）', '{"element":"metal","gain":0.18,"newVal":4.18,"type":"infuse_success"}', 1774376090560),
