(30001, 'Se-01', '棕黃色虎眼石手串', '土', '棕黃色', '這條虎眼石手串主要呈現棕黃色調，在五行中屬於「土」的能量。土代表穩定、踏實、滋養與包容。佩戴這類顏色的手串，可以幫助你增加 grounded 的感覺，提升安全感，讓思緒更清晰，也比較容易累積財富喔！虎眼石本身也有避邪、招財的寓意，是個很不錯的選擇。', '{}', 1, 1, 0, '"2026-03-03T05:14:48.000Z"', '"2026-03-03T05:14:48.000Z"', NULL);

-- Data for divination_sessions (48 rows)
INSERT INTO `divination_sessions` (`id`, `userId`, `topic`, `topicName`, `question`, `adviceJson`, `contextJson`, `dateString`, `energyScore`, `createdAt`) VALUES
(1, 1, 'work', '工作事業', '我們公司要推動晶彩畫的業務，你覺得今天的這方面的工作如何', '{"fortuneIndex":45,"fortuneLabel":"小凶","coreReading":"今日流日乙亥，對您甲木日主而言，乙木為劫財，亥水為偏印。劫財意味著競爭與耗損，尤其在推動新業務如晶彩畫時，可能面臨資源被瓜分或付出多於回收的挑戰。塔羅牌「惡魔」警示您需警惕物質誘惑與執念，避免因急於求成而做出錯誤決策。儘管月相盈凸月帶來能量充盈，但今日主導五行為木，您的忌神過旺，且最弱五行為土，代表財星受損。因此，推動晶彩畫業務需格外謹慎，不宜大張旗鼓，應以穩固根基、防範風險為主。","actions":[{"title":"審慎評估策略","desc":"在劫財耗散之日，應仔細審視晶彩畫業務的推廣方案，確保資源投入與預期回報合理，避免盲目擴張。"},{"title":"鞏固現有客戶","desc":"今日不宜開發新客戶，而是應專注於維護現有關係。劫財可能帶來競爭，確保基本盤穩定是關鍵。"},{"title":"細化財務預算","desc":"由於劫財有財物損失之象，務必精確規劃晶彩畫業務的預算，避免不必要的開支，守住財富。"}],"warnings":"今日因日柱乙亥帶劫財，甲木日主恐遇競爭、財物耗損，推廣晶彩畫業務時，需警惕同行惡性競爭或內部資源分配不均。塔羅惡魔也提醒您，勿被短期利益或物質誘惑蒙蔽，導致決策失誤而造成損失。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"此時為土金旺時，助旺財星與官星，利於規劃。"},{"name":"辰時","time":"07:00-09:00","reason":"辰土為財星，可彌補今日土弱，利於財務審核。"},{"name":"巳時","time":"09:00-11:00","reason":"巳火為食傷，可生財，利於創意發想與溝通。"}],"oracle":"劫財當道守財宜，惡魔誘惑心莫迷。穩固根基待時機，晶彩畫業緩慢推。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"丑","tenGod":"劫財","overallScore":3,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-02', 3, '"2026-03-01T23:32:25.000Z"'),
(30001, 1, 'wealth', '財運金錢', '今天適合打麻將嗎?', '{"fortuneIndex":35,"fortuneLabel":"小凶","coreReading":"今日財運金錢領域面臨挑戰。流日乙亥，對甲木日主而言是劫財，意味著財物易有耗損、競爭，不宜求財冒險。塔羅牌「惡魔」更警示物質誘惑與執念，提醒您警惕不切實際的財富幻想。儘管盈凸月能量充盈，但今日劫財與惡魔牌的雙重影響，使得財運整體偏弱，不宜進行高風險的投機活動，應以守財為上策，避免不必要的支出。","actions":[{"title":"保守理財","desc":"今日劫財星高照，宜避免大額投資或借貸，守住現有財富，因今日財運不佳，冒險易損。"},{"title":"審慎消費","desc":"惡魔牌警示物質誘惑，購物前三思，避免衝動消費，以免不必要的開支加劇財物耗損。"},{"title":"靜心規劃","desc":"利用今日低調保守的能量，檢視財務狀況，為未來理財做規劃，而非急於行動。"}],"warnings":"今日流日劫財，對甲木日主而言財星受損，不宜進行如打麻將等帶有賭博性質的活動，因為容易因競爭而破財，或因一時貪念而損失。塔羅惡魔牌也提醒您，要警惕物質誘惑，避免被不勞而獲的念頭所束縛，否則將陷入財務困境。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"土金旺，利於思考與規劃。"},{"name":"辰時","time":"07:00-09:00","reason":"土旺生金，財星略有轉機。"},{"name":"巳時","time":"09:00-11:00","reason":"火旺，助財運提升，但仍需保守。"}],"oracle":"劫財當道惡魔纏，財星受損莫輕貪。穩守方能避風險，靜待時機再揚帆。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"劫財","overallScore":3,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-02', 3, '"2026-03-02T06:27:10.000Z"'),
(30002, 1, 'work', '工作事業', '今天工作上，在和老闆的報告，有什麼要注意的嗎? 是公司的新推進案子', '{"fortuneIndex":45,"fortuneLabel":"小凶","coreReading":"今日工作事業面臨挑戰，因流日乙亥對甲木日主的你而言是劫財，意味著競爭加劇，或資源被分薄。塔羅牌「惡魔」警示，你可能過於執著於物質成果或某些不健康的關係，這會影響判斷。雖然盈凸月能量充盈，但劫財的影響讓你的提案容易遭遇阻礙或被質疑。特別是新推進的案子，更需謹慎。今日環境五行木旺而土弱，你的喜用神土受克，使得你在表達和爭取資源上會感到力不從心。需以退為進，守住現有成果，避免正面衝突。","actions":[{"title":"簡化報告內容","desc":"今日劫財影響，不宜過於複雜。集中重點，簡潔明瞭地呈現核心價值，避免枝節過多引發爭議。"},{"title":"預設異議與應對","desc":"劫財暗示競爭和阻礙，預先設想老闆可能提出的質疑，準備好有力的數據和論證來應對，展現專業。"},{"title":"強調團隊合作","desc":"今日木氣過旺，劫財易生口舌。在報告中多強調團隊協作與共同利益，避免個人英雄主義，以緩和競爭氛圍。"}],"warnings":"今日劫財與惡魔牌的雙重影響，需警惕在報告中過於強調個人功勞或物質回報，這可能觸發老闆的逆反心理。同時，避免與同事在報告前產生任何形式的爭執，劫財易引發不必要的耗損和糾紛，導致報告效果不佳。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"土氣旺盛，利於思考規劃，為報告打下堅實基礎。"},{"name":"辰時","time":"07:00-09:00","reason":"土氣主事，利於穩定心神，為報告做最後準備。"},{"name":"巳時","time":"09:00-11:00","reason":"火氣漸旺，利於表達，提升報告的說服力與氣勢。"}],"oracle":"劫財當道惡魔纏，謹言慎行守本源。靜待時機方可進，莫貪虛名惹禍端。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"劫財","overallScore":3,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-02', 3, '"2026-03-02T06:34:25.000Z"'),
(60001, 540175, 'work', '工作事業', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"今日壬水日主的你，流日乙亥帶來強烈的傷官能量，預示著在工作事業上將有突破傳統、創新求變的機會。乙木傷官對壬水而言，是才華的展現與思想的輸出，尤其在盈凸月能量加持下，你的創意與表達能力將達到高峰。然而，塔羅惡魔牌提醒你，需警惕過度追求物質或短視近利，以免偏離初心。這股能量有利於你打破僵局，但務必保持清醒，避免因言辭過激而影響人際合作，確保創新能穩健落地。","actions":[{"title":"大膽創新","desc":"今日傷官能量旺盛，宜將新穎想法付諸實踐，尤其在辰時、未時，有助於突破現有框架，展現獨特才華。"},{"title":"溝通表達","desc":"利用傷官的表達能力，積極參與會議或提案，清晰闡述你的創新理念，在巳時進行效果最佳。"},{"title":"審慎評估","desc":"在追求突破時，務必結合實際資源與可行性，避免因一時衝動而做出不切實際的決策，特別注意風險管控。"}],"warnings":"今日流日乙亥，傷官過旺，易導致言辭犀利或行為衝動，可能在職場上無意間得罪他人，損害合作關係。同時，塔羅惡魔牌警示，避免被短期利益或虛榮心所誘惑，以免因急功近利而做出錯誤判斷，影響長遠發展。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"土旺時辰，利於傷官生財，將創新付諸實踐。"},{"name":"未時","time":"13:00-15:00","reason":"土旺時辰，有助於穩定傷官能量，利於規劃與執行。"},{"name":"巳時","time":"09:00-11:00","reason":"火旺時辰，利於傷官吐秀，展現才華，提升表現力。"}],"oracle":"傷官出鞘破舊局，盈月照亮創新途。戒除執念方得自由，金水相生事業榮。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"傷官","overallScore":6,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-02', 6, '"2026-03-02T06:51:35.000Z"'),
(60002, 1, 'work', '工作事業', NULL, '{"fortuneIndex":45,"fortuneLabel":"小凶","coreReading":"今日工作事業面臨挑戰，日柱乙亥對您的甲木日主而言，乙木為劫財，亥水為偏印。劫財意味著競爭加劇，資源易被瓜分，需防範合作糾紛或財務耗損。偏印則可能帶來思慮過多、執行力受阻。塔羅「惡魔」牌警示您，切勿被物質誘惑或過度執念所束縛，這會阻礙您的判斷力。雖然月相盈凸月能量充盈，但劫財的影響仍需謹慎應對。今日環境木氣旺盛，對甲木日主而言，木多為忌，更需避免盲目擴張。保持低調，守成觀望，是今日事業的明智之舉。","actions":[{"title":"保守為上","desc":"今日宜避免重大決策或投資，因劫財影響易有損失，保守行事能減少風險。"},{"title":"專注細節","desc":"偏印可能導致思慮過多，專注於手頭工作的細節，提升執行效率，避免疏漏。"},{"title":"人際和諧","desc":"劫財易引發人際競爭或口舌，今日應多與同事保持良好溝通，避免衝突。"}],"warnings":"今日事業上需特別警惕因競爭而導致的財物損失或合作破裂，因為劫財當令，且流日乙亥的木水組合不利於財運。同時，避免被一時的利益或虛榮心所迷惑，惡魔牌提醒你這些誘惑可能帶來長期的束縛。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"丑土為喜用神，利於穩定與規劃，為今日低谷帶來一絲轉機。"},{"name":"辰時","time":"07:00-09:00","reason":"辰土為喜用神，有助於事業的穩定發展，利於思考與執行。"},{"name":"巳時","time":"09:00-11:00","reason":"巳火為喜用神，火能生土，有助於提升能量，化解木氣過旺。"}],"oracle":"劫財當令宜守成，惡魔警示勿迷途。靜待風過根自固，明朝陽光更燦爛。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"劫財","overallScore":3,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-02', 3, '"2026-03-02T06:58:10.000Z"'),
(60003, 1, 'work', '工作事業', '今天晶彩畫的新事業工作，不知會不會順利，大老闆會不會一直追', '{"fortuneIndex":45,"fortuneLabel":"小凶","coreReading":"今日流日乙亥，對您的甲木日主而言，乙木為劫財，亥水為印星，劫財耗散，印星生身卻也帶來水旺，這與您喜火土金、忌水木的命格形成衝突。劫財能量評分僅3/10，預示著在事業上容易遭遇競爭、資源被瓜分或付出多於收穫。塔羅流日「惡魔」牌，更警示您新事業可能面臨物質誘惑或執念的束縛，需警惕不切實際的承諾或過度投入。雖然盈凸月帶來能量充盈，但今日五行木旺克土（財星），土為您的喜用神，事業財運易受阻。因此，今日新事業的推動會略顯阻滯，需以保守為上策。","actions":[{"title":"保守穩固","desc":"今日劫財當道，不宜大張旗鼓。專注於鞏固現有基礎，避免盲目擴張，以減少不必要的耗損。"},{"title":"細緻規劃","desc":"利用今日亥水印星的能量，沉澱思緒，重新審視新事業的細節與風險，為未來做更周全的準備。"},{"title":"溝通協調","desc":"若遇合作或資源分配問題，宜採取柔和溝通，避免正面衝突，以化解劫財帶來的競爭與摩擦。"}],"warnings":"今日事業上需特別警惕因劫財而來的競爭與資源耗損，避免輕信他人承諾或過度承擔責任。由於木旺克土，土為您的財星與穩定性，新事業的財務投入或回報可能不如預期。同時，惡魔牌警示您需擺脫對物質或成功的執念，以免被錯誤的判斷所束縛，導致大老闆的追問更頻繁。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"土旺時辰，為您的喜用神，利於思考規劃。"},{"name":"辰時","time":"07:00-09:00","reason":"土旺時辰，為您的喜用神，有助於穩定心神。"},{"name":"巳時","time":"09:00-11:00","reason":"火旺時辰，為您的喜用神，可提升行動力與效率。"}],"oracle":"劫財當道勿強求，惡魔誘惑需看透。保守穩固待時機，盈月光華終可求。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"劫財","overallScore":3,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-02', 3, '"2026-03-02T06:59:00.000Z"'),
(60004, 1, 'work', '工作事業', '今天晶彩畫的作品搜集，本來最後交稿是2/23，現在同事都還沒，今天追進度好追嗎?', '{"fortuneIndex":45,"fortuneLabel":"小凶","coreReading":"今日對於您的木日主（甲）而言，流日乙亥為劫財，意味著競爭、耗散與阻礙，特別在合作事務上容易出現不順。塔羅牌「惡魔」更警示您可能因執念或物質誘惑而受困。您本喜火土金，但今日流日五行木旺，且土為最弱，這會加劇您在工作事業上感到根基不穩、付出難見回報的感受。雖然盈凸月帶來能量充盈，但劫財與惡魔的影響力更為顯著，今日追趕進度恐事倍功半，甚至引發不必要的摩擦。宜靜不宜動，守成是上策。","actions":[{"title":"策略性溝通","desc":"今日不宜強硬追逼，可嘗試以關懷或提供協助的方式側面了解進度，因為乙亥劫財日追討易生摩擦。"},{"title":"審視自身工作","desc":"將精力轉向審核自身已完成的部分，或規劃後續步驟，以避免受同事進度影響，因劫財日宜守不宜攻。"},{"title":"準備備用方案","desc":"考慮若同事未能如期交稿的應對措施，如自行補足或調整排程，以應對劫財帶來的潛在變數。"}],"warnings":"今日追進度恐不順，因為流日乙亥為劫財，易導致合作不暢、財物耗散，甚至引發口舌。塔羅惡魔亦提示要警惕因急於求成而落入不必要的糾纏或誘惑，反而讓事情更複雜。最弱五行土，代表根基不穩，此時不宜施壓，以免適得其反。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"土金旺，利於思考規劃，避開日間劫財鋒芒。"},{"name":"辰時","time":"07:00-09:00","reason":"土旺時辰，有助穩固根基，利於內部事務處理。"},{"name":"巳時","time":"09:00-11:00","reason":"火旺時辰，能為您帶來些許暖意與思路，但仍需謹慎。"}],"oracle":"劫財耗財莫強求，惡魔執念易困囚。靜待風過方見日，守成方能穩根由。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"劫財","overallScore":3,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-02', 3, '"2026-03-02T07:01:05.000Z"'),
(60005, 3330308, 'wealth', '財運金錢', NULL, '{"fortuneIndex":78,"fortuneLabel":"吉","coreReading":"今日財運金錢的能量流動，因流日乙亥的食神當令，對您的癸水日主而言，食神生財，才華變現的機遇顯著。食神為才華展現者，意味著您的創意、表達與專業技能是今日財富增長的關鍵。盈凸月高掛，月光充盈，為您的努力帶來聖杯般的豐盛機率。然而，塔羅惡魔牌提醒您，需警惕物質誘惑與執念，避免因追求短期利益而偏離正道，真正的財富源於內在價值的創造與分享。","actions":[{"title":"展現才華","desc":"今日食神能量強勁，宜將您的創意或專業技能公開展示，例如發表作品、提案，或參與需要表達的活動，這將是財富積累的源頭。"},{"title":"投資知識","desc":"今日木火為喜用，食神也代表學習與專研。投資於提升自身技能或知識的課程，長遠來看能為您的財富帶來穩健增長。"},{"title":"分享回饋","desc":"食神亦有分享、付出之意。透過分享您的經驗或提供有價值的服務，不僅能累積人脈，也可能間接帶來意想不到的財富回報。"}],"warnings":"今日塔羅惡魔牌警示，需特別留意物質上的誘惑與執念，切勿因急於求財而做出不理智的投資或消費決策。您的本命土17%較弱，流日環境土0%，需避免因過度追求物質享受而導致財務失衡，保持清醒的頭腦，認清真正的價值所在。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"水氣旺盛，助癸水日主思緒清晰。"},{"name":"寅時","time":"03:00-05:00","reason":"木氣初生，利於食神生財之氣。"},{"name":"卯時","time":"05:00-07:00","reason":"木氣旺盛，為喜用神，助才華展現。"}],"oracle":"食神生財才華顯，盈月高照財源廣。莫為物慾迷心智，清流方能聚金光。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"食神","overallScore":7,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["木","火"],"unfavorableElements":["水","金"],"dayMasterStem":"癸","dayMasterElement":"水"}', '2026-03-02', 7, '"2026-03-02T07:16:31.000Z"'),
(90001, 1, 'wealth', '財運金錢', '今天我要打麻將，你會怎麼建議我在牌桌上的狀況', '{"fortuneIndex":35,"fortuneLabel":"小凶","coreReading":"今日財運金錢方面，因流日乙亥為甲木日主的劫財，意味著財物易有耗損或競爭，尤其在牌桌上更需警惕。塔羅「惡魔」牌提醒您，切勿被一時輸贏或物質誘惑所束縛，執念過深反而傷財。雖然盈凸月能量充盈，但劫財之勢仍強，牌桌上應以保守為上策，避免衝動。今日環境五行木旺，加劇劫財能量，對甲木日主而言，如同樹木過於茂盛，反而互相爭奪養分，不利財富積累。宜靜不宜動，守成勝於進取。","actions":[{"title":"保守為上","desc":"今日劫財當道，不宜大額投入或冒險，小玩怡情，避免因牌局而造成財務壓力。"},{"title":"觀察為主","desc":"先觀察牌局走勢，不急於出牌或搶攻，等待有利時機，減少不必要的損失。"},{"title":"見好就收","desc":"若有小贏，應果斷離場，切勿戀戰，避免因貪念而將贏得的又吐回去。"}],"warnings":"今日劫財能量強勁，加上塔羅惡魔的物質誘惑，牌桌上易因衝動、貪婪而導致財物損失。忌神木旺，更會加劇劫財的負面影響，切勿與人爭鋒或意氣用事，否則財散人傷。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"土金能量稍顯，可稍緩劫財之勢，但仍需謹慎。"},{"name":"辰時","time":"07:00-09:00","reason":"土氣略增，有助於財運穩定，但非大旺。"},{"name":"巳時","time":"09:00-11:00","reason":"火土金能量稍有提升，但劫財仍是主導，宜保守。"}],"oracle":"劫財當道惡魔誘，盈月雖滿財易流。牌桌宜守不宜攻，靜待風過方可留。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"巳","tenGod":"劫財","overallScore":3,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-02', 3, '"2026-03-02T07:46:19.000Z"'),
(120001, 6390033, 'decision', '重要決策', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"今日對於壬水日主的您而言，流日乙亥帶來強烈的傷官能量，代表著突破舊有框架、創新思維的絕佳時機。乙木傷官出鞘，您的智慧與表達能力被激發，適合在決策中展現獨到見解。月相盈凸月，能量充盈，為您的決策增添了助力與聖杯機率。然而，塔羅惡魔牌提醒您，在做重要決策時，需警惕物質誘惑與執念，避免被表象所困。結合您的喜用神為水金，今日流日水金能量雖非最強，但傷官的突破性配合月相的豐盛，是您大膽創新、跳脫常規的良機。","actions":[{"title":"大膽創新決策","desc":"今日傷官能量強勁，適合跳脫傳統思維，提出或採納具有突破性的決策，因為此時您的創意與洞察力最佳。"},{"title":"溝通表達清晰","desc":"傷官也代表表達能力，將您的決策理念清晰且有邏輯地闡述，能有效說服他人，推動決策執行。"},{"title":"審視潛在風險","desc":"在決策前務必深入評估，尤其要提防因物質利益或過度自信而導致的判斷失誤，惡魔牌警示不可輕忽。"}],"warnings":"今日做重要決策時，需特別警惕因過於追求創新或表達直接而得罪他人，導致人際關係受損。同時，塔羅惡魔牌提示，避免被短期利益或執念蒙蔽雙眼，做出後悔的決定。流日木旺而土弱，您的本命土也偏弱，需防決策過於理想化而缺乏穩固基礎。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"今日最旺時辰之一，有利於清晰思考。"},{"name":"巳時","time":"09:00-11:00","reason":"今日最旺時辰之一，有利於決策執行。"},{"name":"未時","time":"13:00-15:00","reason":"今日最旺時辰之一，有利於決策實施。"}],"oracle":"傷官出鞘破舊局，盈月照亮決策路；心明眼亮避誘惑，突破創新聖杯足。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"未","tenGod":"傷官","overallScore":6,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-02', 6, '"2026-03-02T10:07:00.000Z"'),
(120002, 6390033, 'health', '健康身心', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"今日壬水日主，流日乙亥，乙木傷官透出，對您而言，這股能量是挑戰舊有健康習慣、尋求身心突破的契機。傷官代表創新與表達，意味著您可能會對現有的養生方式產生質疑，渴望嘗試新的健康理念。然而，流日主導五行為木，而您的喜用神為金水，忌神為木火，今日木氣較旺，雖然有助於創新，但也易耗損心神。塔羅「惡魔」牌警示，需留意身心是否被不良習慣或物質慾望束縛，避免過度放縱。盈凸月能量充盈，提供您轉化的力量，但需智慧引導，方能將這股能量轉化為身心健康的正面推動力。","actions":[{"title":"嘗試新運動","desc":"今日傷官能量旺盛，適合突破常規。嘗試瑜伽、冥想或戶外活動，能有效釋放身心壓力，活絡氣血。"},{"title":"調整飲食結構","desc":"流日木旺，易生肝氣鬱結。可多攝取金水屬性食物如白色食物、黑色食物，滋養腎水，平衡五行。"},{"title":"檢視不良習慣","desc":"惡魔牌提醒檢視執念與束縛。今日是戒除熬夜、過度飲食或沉迷電子產品等不良習慣的好時機。"}],"warnings":"今日流日乙亥，乙木傷官，木氣過旺易耗損壬水元氣，導致情緒波動或肝火旺盛。塔羅惡魔牌警示，需警惕物質誘惑與執念對健康的負面影響，例如暴飲暴食、過度消費導致身心失衡。同時，傷官克官，言辭過激可能引發人際矛盾，間接影響心理健康。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"土金相生，利於脾胃消化與身心穩定。"},{"name":"未時","time":"13:00-15:00","reason":"土氣得生，助於穩定心神，適合靜養。"},{"name":"巳時","time":"09:00-11:00","reason":"火土相生，提升活力，但需注意情緒管理。"}],"oracle":"傷官出鞘破執念，盈月引光照心田。水潤金生身心健，惡魔警示莫貪戀。"}', '{"dayPillar":"乙亥","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"未","tenGod":"傷官","overallScore":6,"tarotCard":"惡魔","tarotKeywords":["束縛","物質","誘惑"],"moonPhase":"盈凸月","moonLunarDay":14,"dominantElement":"木","weakestElement":"土","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-02', 6, '"2026-03-02T10:09:40.000Z"'),
(150001, 1, 'work', '工作事業', NULL, '{"fortuneIndex":85,"fortuneLabel":"大吉","coreReading":"老弟，今天在工作事業上，你簡直是火力全開啊！因為今天的天象，特別是那個「傷官」的能量，對你這個屬木的日主來說，就像是給你加了一把火，讓你腦袋特別靈光，特別想搞點新東西。這股勁兒會讓你很有突破性，那些舊規矩、老方法，你今天特別有機會去挑戰它，甚至想出更好的辦法。你的想法會像星星一樣閃亮，充滿希望。這時候，你的創意就是你最鋒利的武器，好好利用它，去開創屬於你的一片天！","actions":[{"title":"大膽創新","desc":"別怕提出新點子，今天你的創意特別值錢。勇敢地把你的想法說出來，甚至動手去嘗試，會有意想不到的好結果。"},{"title":"把握表達","desc":"今天你表達能力特別強，適合做簡報、談判或溝通。把你的想法清晰地傳達出去，會更容易獲得支持和認同。"},{"title":"重點突破","desc":"選一個你覺得最難搞、最需要創新突破的項目，把精力集中在那上面。今天的能量會幫你找到解決方案。"}],"warnings":"雖然今天你很有衝勁，但說話的時候還是要多留心。有時候太直接、太想突破，可能會不小心傷到人。記得多點耐心，保持和氣，這樣你的好點子才能被更好地接受。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時候思緒清晰，適合規劃和沉澱想法。"},{"name":"午時","time":"11:00-13:00","reason":"火的能量最強，有利於展現才華和溝通。"},{"name":"未時","time":"13:00-15:00","reason":"土的能量穩定，適合將創意付諸實踐。"}],"oracle":"今日星光引領，勇破舊局，你的光芒將照亮前路，無所不能！"}', '{"dayPillar":"丁丑","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"寅","tenGod":"傷官","overallScore":7,"tarotCard":"星星","tarotKeywords":["希望","靈感","療癒"],"moonPhase":"虧凸月","moonLunarDay":16,"dominantElement":"火","weakestElement":"水","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-04', 7, '"2026-03-04T00:09:31.000Z"'),
(180001, 660061, 'work', '工作事業', NULL, '{"fortuneIndex":70,"fortuneLabel":"吉","coreReading":"老弟，你今天在工作事業上會感覺特別有頭腦，很多事情都能看得很透徹。因為今天的主導能量是那種讓人沉靜下來思考的，對你這個踏實的己土來說，這就像是給你充足的時間去整理思緒、學習新東西。你可能會突然冒出一些很棒的點子，或者對手上的項目有更深的理解。這不是一個衝鋒陷陣的日子，而是適合好好沉澱、累積實力。相信你的直覺，它今天會特別準，能幫你避開不少彎路。放鬆心情，好好享受這種智慧沉澱的感覺，你會發現很多問題的答案就在不經意間浮現。加油，你行的！","actions":[{"title":"深入研究","desc":"今天特別適合花時間去深入了解一個項目或學習新技能。把那些需要動腦筋、鑽研細節的工作拿出來，你會發現效率特別高。"},{"title":"整理思緒","desc":"把工作上的雜事、待辦事項好好整理一下，列出優先順序。這能讓你思路更清晰，為接下來的行動做好準備。"},{"title":"信任直覺","desc":"在做決策時，除了邏輯分析，也多聽聽自己內心的聲音。今天你的直覺很靈敏，有時候它會給你意想不到的答案。"}],"warnings":"今天雖然適合思考，但也要小心別鑽牛角尖，想太多反而會讓自己陷入困境。有時候，過度分析會讓你錯失一些簡單的機會。另外，溝通時要留意，可能會有誤解發生，所以表達要盡量清楚明白。","bestHours":[{"name":"午時","time":"11:00-13:00","reason":"這段時間你的思路最清晰，最適合處理重要事務。"},{"name":"未時","time":"13:00-15:00","reason":"智慧能量充沛，有利於學習和解決複雜問題。"},{"name":"巳時","time":"09:00-11:00","reason":"工作效率高，適合開啟需要專注的任務。"}],"oracle":"靜心沉澱，智慧自來，今日所思，皆為明日之基石。"}', '{"dayPillar":"丁丑","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"辰","tenGod":"偏印","overallScore":5,"tarotCard":"月亮","tarotKeywords":["幻象","直覺","潛意識"],"moonPhase":"虧凸月","moonLunarDay":16,"dominantElement":"火","weakestElement":"水","favorableElements":["土","火"],"unfavorableElements":["金","水"],"dayMasterStem":"己","dayMasterElement":"土"}', '2026-03-04', 5, '"2026-03-04T04:11:12.000Z"'),
(180002, 660061, 'wealth', '財運金錢', NULL, '{"fortuneIndex":65,"fortuneLabel":"吉","coreReading":"兄弟，今天你的財運金錢方面，整體來說是個不錯的日子，但需要你多動腦筋、多思考。因為今天的天象對你這個屬土的人來說，是個讓你直覺特別敏銳、想法特別多的時候。這代表你在處理錢的事情上，可能會有很多新的點子冒出來，或者對一些投資機會有更深的洞察。這不是那種天上掉餡餅的財運，而是需要你用心去研究、去判斷才能抓住的機會。好好利用這份直覺，你會發現不一樣的可能！","actions":[{"title":"深入研究","desc":"今天特別適合去研究那些你感興趣的投資項目或理財產品，多花時間去了解細節，你會發現一些別人沒看到的機會。"},{"title":"整理財務","desc":"趁著今天思緒清晰，把自己的收支明細、帳務好好整理一下，搞清楚錢都花到哪去了，這樣能幫你省下不少錢。"},{"title":"聽從直覺","desc":"如果遇到跟錢有關的選擇，在理性分析的基礎上，也多聽聽你內心的聲音。有時候，最準的判斷就藏在直覺裡。"}],"warnings":"今天在財運上，要留意別想太多鑽牛角尖，有時候過度思考反而會讓你錯失良機。另外，也要小心一些表面光鮮但實質不清的投資建議，多方查證，不要輕易被表象迷惑了。","bestHours":[{"name":"午時","time":"11:00-13:00","reason":"這段時間你的判斷力特別好，適合做決定。"},{"name":"未時","time":"13:00-15:00","reason":"思路清晰，有助於深入思考財務問題。"},{"name":"巳時","time":"09:00-11:00","reason":"精神飽滿，適合規劃和學習新的理財知識。"}],"oracle":"靜心沉澱，智慧自來，財路不求自開。"}', '{"dayPillar":"丁丑","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"辰","tenGod":"偏印","overallScore":5,"tarotCard":"月亮","tarotKeywords":["幻象","直覺","潛意識"],"moonPhase":"虧凸月","moonLunarDay":16,"dominantElement":"火","weakestElement":"水","favorableElements":["土","火"],"unfavorableElements":["金","水"],"dayMasterStem":"己","dayMasterElement":"土"}', '2026-03-04', 5, '"2026-03-04T04:29:06.000Z"'),
(210001, 7740633, 'health', '健康身心', NULL, '{"fortuneIndex":65,"fortuneLabel":"吉","coreReading":"老弟，今天你的丁火日主遇到丁丑日，這就像是自己跟自己較勁，精力會比較旺盛，但也要注意別把自己繃得太緊。因為今天火的能量特別強，容易感到心浮氣躁，甚至有點上火。加上塔羅牌說要轉變、要放下，這時候如果身體和心靈上有什麼舊的包袱，現在就是好好整理、放下的時候。別硬撐，給自己一點空間，你會發現新的開始就在不遠處。你很棒，一定能找到平衡！","actions":[{"title":"多喝水降火","desc":"今天火氣比較大，記得多補充水分，喝點涼茶或溫開水，幫身體降降溫，別讓自己太燥熱。"},{"title":"靜心休息","desc":"雖然精力旺盛，但也要適時讓心靜下來。可以試著冥想幾分鐘，或找個安靜的地方放鬆一下，別讓自己過度消耗。"},{"title":"適度運動","desc":"把多餘的精力透過溫和的運動釋放出來，例如散步、瑜伽或伸展，但避免過於劇烈，以免加重身體負擔。"}],"warnings":"今天要注意情緒起伏可能會比較大，容易因為一點小事就心煩意亂，甚至影響睡眠。身體上也要留意上火、發炎或消化道不適的問題。別太鑽牛角尖，給自己留點彈性空間。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"此時段能量平穩，適合深層休息。"},{"name":"申時","time":"15:00-17:00","reason":"金氣旺盛，能幫助你沉澱心緒。"},{"name":"酉時","time":"17:00-19:00","reason":"金氣持續，適合放鬆與整理思緒。"}],"oracle":"心靜如水，自有清涼。放下執念，輕盈前行。"}', '{"dayPillar":"丁丑","monthPillar":"庚寅","yearPillar":"丙午","hourBranch":"酉","tenGod":"比肩","overallScore":5,"tarotCard":"死神","tarotKeywords":["轉變","結束","新生"],"moonPhase":"虧凸月","moonLunarDay":16,"dominantElement":"火","weakestElement":"水","favorableElements":["土","金"],"unfavorableElements":["火","木"],"dayMasterStem":"丁","dayMasterElement":"火"}', '2026-03-04', 5, '"2026-03-04T15:55:22.000Z"'),
(240001, 5880001, 'love', '愛情感情', NULL, '{"fortuneIndex":70,"fortuneLabel":"吉","coreReading":"兄弟，今天在感情上，你會感覺自己特別有責任感，也渴望關係能穩定下來。因為今天的天象，就像是給你套上了一層規矩和認真負責的光環。你對感情會比較看重承諾和未來，也容易吸引到那些欣賞你穩重踏實特質的人。如果你有心儀對象，今天很適合展現你可靠的一面。如果你在關係中，今天也是個好好規劃兩人未來的好時機。別擔心，穩穩地走，幸福就在前方。","actions":[{"title":"展現穩重","desc":"今天在感情交流中，多表現你的成熟和可靠，讓對方感受到你的認真和值得信賴，這會很有幫助。"},{"title":"規劃未來","desc":"如果你有伴侶，可以和對方聊聊對未來的想法，或是共同設定一些小目標，讓關係更堅固。"},{"title":"尋求建議","desc":"如果感情上有困惑，可以找一位你信任的長輩或有經驗的朋友聊聊，他們的智慧能給你指引。"}],"warnings":"今天雖然適合穩固感情，但也可能因為太過於看重規矩，顯得不夠靈活或浪漫。有時候，太過理性可能會讓氣氛變得嚴肅，記得偶爾也要放鬆一下，多點輕鬆的互動，讓感情保持活力。","bestHours":[{"name":"申時","time":"15:00-17:00","reason":"這時候你的能量最旺，適合真誠表達心意。"},{"name":"酉時","time":"17:00-19:00","reason":"這時段思緒清晰，適合深入交流，解決問題。"},{"name":"未時","time":"13:00-15:00","reason":"這時段氣氛輕鬆，適合約會或開展新話題。"}],"oracle":"今日穩重踏實，感情之路更顯光明，勇敢向前，幸福自來。"}', '{"dayPillar":"己卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"亥","tenGod":"正官","overallScore":5,"tarotCard":"教皇","tarotKeywords":["傳統","智慧","指引"],"moonPhase":"虧凸月","moonLunarDay":18,"dominantElement":"木","weakestElement":"水","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-06', 5, '"2026-03-05T18:16:23.000Z"'),
(270001, 540175, 'work', '工作事業', NULL, '{"fortuneIndex":85,"fortuneLabel":"吉","coreReading":"兄弟，今天對你來說，在工作事業上是個展現能力、站穩腳步的好日子！因為今天的天象，特別是日柱己卯，對你這個壬水日主來說，就像是遇到了一個能讓你發揮所長的平台。你平常的努力和規矩，今天會特別被看見，有機會得到上司或同事的肯定。雖然今天環境裡『水』的能量比較弱，可能會讓你感覺少了點助力，但別擔心，你的實力就是最好的後盾。好好把握，今天你會感覺一切都順理成章，充滿了自信和活力！","actions":[{"title":"主動提案","desc":"今天適合把腦子裡的好點子說出來，特別是那些有條理、有規劃的方案，更容易被採納。"},{"title":"溝通交流","desc":"跟上級或重要客戶溝通時，保持專業和禮貌，你的意見會更有份量，容易達成共識。"},{"title":"整理規劃","desc":"利用今天的好能量，把手邊的工作好好整理一番，制定清晰的下一步計畫，效率會很高。"}],"warnings":"今天雖然整體運勢不錯，但也要注意，環境中『水』的能量比較少，這可能會讓你偶爾感到有些疲憊或想法不夠流暢。記得適時休息，補充水分，別讓自己過度消耗。在做決策時，多一份耐心，避免急躁。","bestHours":[{"name":"未時","time":"13:00-15:00","reason":"此刻思緒清晰，適合做重要決策。"},{"name":"申時","time":"15:00-17:00","reason":"工作效率高，容易有突破性進展。"},{"name":"酉時","time":"17:00-19:00","reason":"有利於收尾工作，成果被看見。"}],"oracle":"今日規則為你所用，展現真我，成就非凡，你的光芒，無人能擋。"}', '{"dayPillar":"己卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"丑","tenGod":"正官","overallScore":5,"tarotCard":"太陽","tarotKeywords":["成功","喜悅","活力"],"moonPhase":"虧凸月","moonLunarDay":18,"dominantElement":"木","weakestElement":"水","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-06', 5, '"2026-03-05T23:01:50.000Z"'),
(270002, 540175, 'work', '工作事業', '請問我明天兩個面試狀況會不會順利呢？我該避免什麼？建議以什麼心態來面對', '{"fortuneIndex":85,"fortuneLabel":"吉","coreReading":"兄弟，你明天有兩個面試，心裡肯定有點緊張吧？別擔心，今天的天象對你可是很有利的！因為今天日主是己卯，對你這個壬水日主來說，就像是遇到了一個能讓你好好發揮的舞台，特別適合處理正式的事情，面試這種場合更是被天命護佑。所以，放寬心去展現你自己，機會就在眼前。記住，你是最棒的，拿出你的實力就好！","actions":[{"title":"展現專業與規範","desc":"面試時要表現出你對規則的理解和對工作的認真態度。穿著得體，言談舉止都要專業，這會讓對方對你印象深刻。"},{"title":"自信表達想法","desc":"今天的塔羅是太陽牌，代表成功和活力。面試時要自信地表達你的想法和經驗，讓你的光芒自然散發出來，不要畏縮。"},{"title":"準備充分資料","desc":"面試前把所有需要的資料都整理好，包括履歷、作品集等。準備越充分，你心裡就越有底氣，表現也會更穩健。"}],"warnings":"今天雖然整體運勢很好，但也要注意別因為太過自信而忽略了細節，或者在溝通時顯得太過強勢。保持謙遜，多聽少說，這樣會讓你的表現更圓融，也更能贏得面試官的好感。","bestHours":[{"name":"申時","time":"15:00-17:00","reason":"這段時間你的能量最旺，思路清晰，表達流暢。"},{"name":"酉時","time":"17:00-19:00","reason":"此時段運勢持續高漲，有利於收尾和留下好印象。"},{"name":"未時","time":"13:00-15:00","reason":"下午剛開始，精神飽滿，適合展現你的活力與專業。"}],"oracle":"今日規則為你開路，自信光芒照亮前程，勇敢邁步，成功就在不遠處！"}', '{"dayPillar":"己卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"丑","tenGod":"正官","overallScore":5,"tarotCard":"太陽","tarotKeywords":["成功","喜悅","活力"],"moonPhase":"虧凸月","moonLunarDay":18,"dominantElement":"木","weakestElement":"水","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-06', 5, '"2026-03-05T23:03:07.000Z"'),
(270003, 1, 'decision', '重要決策', '明天上班，我11:00就會和同事去經銷商的告別公祭，pm1:30開始，結束離開應該會是2-3點，之後我打算直接離開公司去剪頭髮，整個狀況下來，有什麼要注意的嗎?', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"老弟，你明天這個行程安排，去告別公祭又接著去剪頭髮，其實挺好的。今天整體運勢是穩健累積的，雖然不是那種大鳴大放衝刺的日子，但你處理這些事情，特別是告別公祭這種需要沉穩應對的場合，會做得很好。因為你日主是木，今天日柱己卯是正財，意味著你處理這些人際關係和個人事務，會顯得特別踏實和有條理。剪頭髮這個個人事務，也算是一種整理和收穫，跟今天的能量很搭。放心去吧，你處理得來，而且會讓自己感覺更清爽，為接下來的日子做好準備。","actions":[{"title":"告別公祭：專注沉穩","desc":"在公祭現場，保持沉穩和尊重，你的木行日主會讓你顯得有禮有節，給人留下好印象。好好送別，這份心意很重要。"},{"title":"個人事務：提早規劃","desc":"既然要去剪頭髮，提前跟髮型師確認好時間，確保你離開公司後能順利銜接。把時間抓緊，讓自己從容不迫。"},{"title":"工作交接：細心交代","desc":"雖然是個人行程，但離開公司前，把手邊重要的工作跟同事交代清楚，讓大家知道你的去向和預計回來時間，這樣大家都會很放心。"}],"warnings":"今天雖然整體不錯，但因為主導五行是木，而你的喜用神是火、土、金，最弱五行是水。所以要注意一下，在處理人際關係時，雖然你很穩重，但也要避免過於固執己見，多聽聽別人的意見。另外，今天水氣比較弱，可能會有口乾舌燥的感覺，記得多補充水分，保持身體舒適。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時候處理公祭前的準備或溝通，會特別順暢。"},{"name":"巳時","time":"09:00-11:00","reason":"公祭前夕，適合做最後確認，讓一切準備就緒。"},{"name":"午時","time":"11:00-13:00","reason":"公祭進行時段，你的沉穩會幫助你好好應對，能量很足。"}],"oracle":"穩健前行，每一步都算數；整理思緒，讓自己煥然一新。"}', '{"dayPillar":"己卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"丑","tenGod":"正財","overallScore":5,"tarotCard":"太陽","tarotKeywords":["成功","喜悅","活力"],"moonPhase":"虧凸月","moonLunarDay":18,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-06', 5, '"2026-03-05T23:14:42.000Z"'),
(270004, 1, 'decision', '重要決策', '明天早上到下午要參加公祭，之後去剪頭髮，晚上和朋友聚會吃飯看2026wbc台灣對日本，明天我的穿搭顏色，都是屬水偏黑色和藍色ok嗎，手串上你覺得怎麼樣比較好', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"老弟，明天你行程排得滿滿的，公祭、剪髮、朋友聚會，還要看球賽，真是充實啊！針對你的穿搭，你日主是木，喜用火、土、金，忌水、木。明天雖然是木氣旺的一天，但你穿水色（黑、藍）會讓你的木氣更旺，這不是你最需要的。公祭穿深色沒問題，但如果能加點土色或金色系的配件，或內搭，會讓你的氣場更穩。晚上聚會看球賽，就是要開心，穿得舒服自在最重要。手串的話，選個暖色調的，像紅色、橘色，或者金屬色的，會幫你把氣場調得更好，讓你一整天都順順利利，充滿活力！","actions":[{"title":"穿搭建議","desc":"公祭穿深色可以，但建議避開全身黑藍。可以搭配米白、卡其、咖啡色或金色系的配件，讓整體氣場更平衡。"},{"title":"手串搭配","desc":"選擇紅、橘、黃等暖色系的手串，或是金屬材質的飾品，能幫你增添好運，讓心情更開朗。"},{"title":"髮型更新","desc":"剪頭髮是個好時機，換個新造型，換個心情，能讓你整個人煥然一新，迎接好運。"}],"warnings":"明天雖然整體運勢不錯，但因為環境中木氣比較重，你又是木日主，可能會感覺有點衝動或想太多。做重要決定前，多給自己一點時間思考，別急著下定論，穩穩地來就好。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時段氣場最旺，處理事情會更順暢。"},{"name":"巳時","time":"09:00-11:00","reason":"能量充沛，適合需要專注和活力的事務。"},{"name":"午時","time":"11:00-13:00","reason":"火氣旺盛，能幫你提升精氣神，做什麼都帶勁。"}],"oracle":"穩紮穩打，步步為營，你的努力終將化為豐盛的收穫，加油！"}', '{"dayPillar":"己卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"丑","tenGod":"正財","overallScore":5,"tarotCard":"太陽","tarotKeywords":["成功","喜悅","活力"],"moonPhase":"虧凸月","moonLunarDay":18,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-06', 5, '"2026-03-05T23:19:12.000Z"'),
(300001, 1, 'health', '健康身心', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"老弟，今天對你的健康來說是個不錯的日子，可以說是充滿活力。因為今天的主導五行是木，雖然你本身就是木，但今天同時也有火的能量來幫你消化多餘的木氣，讓你的身體和精神都能找到一個平衡點。就像你身體裡有股力量，今天這股力量特別足，但同時也有個出口讓你好好運用，不會悶在心裡。所以，你會感覺比較有精神，心情也容易開朗。好好把握這股能量，做些讓自己身心都舒服的事情，你會感覺很棒的！","actions":[{"title":"多活動筋骨","desc":"今天身體的能量很足，去戶外走走、做些輕度運動，讓身體動起來，把這股活力好好釋放出來。"},{"title":"親近大自然","desc":"找個公園或綠地，多接觸花草樹木，讓自己沉浸在自然的氛圍裡，能幫助你放鬆心情，吸收好的能量。"},{"title":"好好吃飯","desc":"今天胃口可能不錯，別忘了均衡飲食。多吃些溫和的食物，讓身體保持在最佳狀態。"}],"warnings":"今天雖然活力滿滿，但也要注意別過度消耗自己。尤其在情緒上，如果遇到不順心的事，可能會有點固執，記得適時放鬆，別讓小事影響了你的好心情。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時候精神最好，適合開始一天的活動。"},{"name":"巳時","time":"09:00-11:00","reason":"活力充沛，做運動或處理事情效率高。"},{"name":"午時","time":"11:00-13:00","reason":"陽光正好，適合外出走動，吸收正能量。"}],"oracle":"今日身心皆得滋養，活力滿盈，順勢而為，自得其樂。"}', '{"dayPillar":"己卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"戌","tenGod":"正財","overallScore":5,"tarotCard":"太陽","tarotKeywords":["成功","喜悅","活力"],"moonPhase":"虧凸月","moonLunarDay":18,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土","金"],"unfavorableElements":["水","木"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-06', 5, '"2026-03-06T16:51:01.000Z"'),
(300002, 4440001, 'work', '工作事業', NULL, '{"fortuneIndex":85,"fortuneLabel":"大吉","coreReading":"兄弟，今天對你的工作事業來說，是個非常給力的日子！因為今天的天象，特別有利於你處理那些需要規矩、講流程的事情。你就像一棵挺拔的樹，在明確的框架裡反而能展現最好的狀態。所以，無論是開會、談合作，還是簽文件，都會特別順利。別怕展現你的能力，今天就是你閃耀的時候。放手去做，成功就在眼前，你一定行的！","actions":[{"title":"勇敢展現","desc":"今天適合在會議上發言、提出你的想法，或者在面試中自信地表現自己，你會給人留下好印象。"},{"title":"處理正式事務","desc":"簽訂合約、處理法律文件、提交報告等，今天處理這些事情會特別順利，阻礙較少。"},{"title":"溝通上司","desc":"如果你有什麼想法想跟主管說，或者需要他們的批准，今天去溝通，成功的機會會大大增加。"}],"warnings":"今天雖然整體運勢很好，但要留意，環境中火的能量比較強，可能會讓你感覺有些急躁或壓力。記得適時讓自己放鬆一下，保持內心的平靜，這樣做事情會更穩妥。別讓一時的衝動影響了你的好運氣。","bestHours":[{"name":"申時","time":"15:00-17:00","reason":"金的能量強，有利於溝通與執行，能讓事情更順利。"},{"name":"酉時","time":"17:00-19:00","reason":"金的能量持續旺盛，是收尾和確認成果的好時機。"},{"name":"子時","time":"23:00-01:00","reason":"水的能量帶來智慧與平靜，適合思考與規劃，為明天做準備。"}],"oracle":"今日規則為你所用，自信前行，每一步都踏實有力！"}', '{"dayPillar":"庚辰","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"子","tenGod":"正官","overallScore":6,"tarotCard":"太陽","tarotKeywords":["成功","喜悅","活力"],"moonPhase":"虧凸月","moonLunarDay":19,"dominantElement":"火","weakestElement":"水","favorableElements":["木","水"],"unfavorableElements":["火","土"],"dayMasterStem":"乙","dayMasterElement":"木"}', '2026-03-07', 6, '"2026-03-06T21:03:11.000Z"'),
(300003, 7890138, 'work', '工作事業', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，今天對你的工作事業來說是個不錯的日子！因為今天的天象顯示，財富會以一種穩健、慢慢累積的方式向你靠近。這不是那種一夜暴富的機會，而是你過去努力的累積，現在開始看到成果。特別是今天，你日主是丁火，而流日是庚辰，這代表著你今天在事業上會遇到很多穩定的機會，適合你好好規劃財務，把錢用在刀刃上。所以，別急著衝刺，把手上的事情做得更紮實，為未來打好基礎，這才是今天最聰明的做法。相信自己，每一步都算數！","actions":[{"title":"穩健投資","desc":"今天很適合評估手上的投資項目，或是開始規劃新的財務計畫，以長期穩健為目標，別急功近利。"},{"title":"細節深耕","desc":"把工作中的每一個細節都處理好，不要放過任何一個小地方，這些都會是你未來成功的基石。"},{"title":"人際和諧","desc":"今天在職場上多跟同事、合作夥伴保持良好關係，多溝通，有助於事情順利推進，甚至帶來好機會。"}],"warnings":"今天雖然整體運勢不錯，但要留意別因為太過專注於細節而忽略了大的方向，有時候也要抬頭看看遠方。另外，今天火的能量比較強，可能會讓你有點急躁，記得保持冷靜，別衝動做決定，特別是和錢有關的事情。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時候頭腦清晰，適合做規劃和決策。"},{"name":"未時","time":"13:00-15:00","reason":"這個時段能量旺盛，有利於推進重要事務。"},{"name":"巳時","time":"09:00-11:00","reason":"溝通順暢，適合與人交流合作。"}],"oracle":"穩紮穩打，步步為營，今日之耕耘，明日之豐收。"}', '{"dayPillar":"庚辰","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"未","tenGod":"正財","overallScore":7,"tarotCard":"戀人","tarotKeywords":["選擇","愛情","和諧"],"moonPhase":"虧凸月","moonLunarDay":19,"dominantElement":"火","weakestElement":"水","favorableElements":["土","金"],"unfavorableElements":["火","木"],"dayMasterStem":"丁","dayMasterElement":"火"}', '2026-03-07', 7, '"2026-03-07T10:39:26.000Z"'),
(330001, 1, 'decision', '重要決策', '中華隊這次會進owb2026嗎', '{"fortuneIndex":65,"fortuneLabel":"吉","coreReading":"兄弟，你問中華隊能不能進OWB2026，這問題問得好！不過，我這邊的分析是針對你個人今天的運勢，不是預測球隊比賽結果喔。今天對你來說，是個適合靜心思考、沉澱智慧的好日子。你的直覺特別靈敏，很多事情看得很透徹。所以，與其去想球隊的結果，不如把這份專注力用在自己身上，好好規劃一下你自己的下一步，你會發現很多以前沒想到的好點子。相信我，把自己顧好，就是最好的開始！","actions":[{"title":"深度思考","desc":"今天頭腦特別清楚，適合一個人靜下來，好好想清楚接下來想做什麼，別急著行動。"},{"title":"學習新知","desc":"可以看些書、聽些講座，或是研究感興趣的事物，今天吸收力特別好，會有收穫。"},{"title":"整理思緒","desc":"把腦子裡亂七八糟的想法寫下來，或是跟信任的朋友聊聊，會讓思路更清晰。"}],"warnings":"今天雖然適合思考，但也要小心別鑽牛角尖，想太多反而會讓自己累。有時候，放下一些執著，讓心靈放鬆，反而能找到更好的答案。別讓過度思慮影響了心情。","bestHours":[{"name":"午時","time":"11:00-13:00","reason":"這時候你的能量特別旺，做什麼都順。"},{"name":"未時","time":"13:00-15:00","reason":"運氣持續高漲，適合處理重要事情。"},{"name":"丑時","time":"01:00-03:00","reason":"夜深人靜，適合沉思和規劃未來。"}],"oracle":"靜心沉澱，智慧自來，你的每一步都充滿力量！"}', '{"dayPillar":"壬午","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"子","tenGod":"偏印","overallScore":5,"tarotCard":"愚者（22）","tarotKeywords":["大智若愚","圆滿归零","超越智慧"],"moonPhase":"虧凸月","moonLunarDay":21,"dominantElement":"火","weakestElement":"土","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-09', 5, '"2026-03-09T19:09:35.000Z"'),
(360001, 1, 'decision', '重要決策', '今天適合幫公司送產品給合作的K O L嗎？', '{"fortuneIndex":85,"fortuneLabel":"大吉","coreReading":"老弟，今天絕對是個好日子，非常適合你幫公司把產品送給合作的KOL！你看，今天你就像一棵被滋潤的大樹，充滿活力。而且啊，今天特別容易得到別人的幫助和支持，KOL收到產品後，也會更樂意幫你推廣。這時候去送，就像是順水推舟，事情會很順利。放手去做吧，今天的好運會幫你一把！","actions":[{"title":"大膽推進","desc":"今天去送產品給KOL，成功機率高，他們會很樂意接受，甚至主動幫忙推廣。"},{"title":"尋求建議","desc":"如果KOL有什麼想法或建議，今天特別適合傾聽和採納，會帶來意想不到的好結果。"},{"title":"展現誠意","desc":"送產品時多聊幾句，展現你的真誠和對合作的重視，能加深彼此的關係。"}],"warnings":"今天整體運勢很不錯，但還是要記得，在溝通時保持耐心和細心，避免因為小細節而產生誤會。尤其在文件或承諾方面，多確認幾次會更好喔。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"能量旺盛，適合開啟新行動。"},{"name":"巳時","time":"09:00-11:00","reason":"火土能量強，有利於溝通與合作。"},{"name":"午時","time":"11:00-13:00","reason":"火氣最旺，推動事情會很順暢。"}],"oracle":"今日貴人相助，事半功倍。放膽去做，成功就在眼前！"}', '{"dayPillar":"癸未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"辰","tenGod":"正印","overallScore":5,"tarotCard":"教皇","tarotKeywords":["傳統","智慧","指引"],"moonPhase":"下弦月","moonLunarDay":22,"dominantElement":"火","weakestElement":"金","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-10', 5, '"2026-03-10T03:59:42.000Z"'),
(360002, 1, 'work', '工作事業', '今天適合幫公司送產品給合作的K O L嗎？', '{"fortuneIndex":85,"fortuneLabel":"吉","coreReading":"老弟，今天絕對是個好日子，非常適合你幫公司把產品送給合作的KOL！你看，今天你就像被滋潤的參天大樹，充滿活力。流日天象顯示，今天有貴人和支持圍繞著你，送產品這事兒，KOL會很樂意接受，甚至會給你帶來意想不到的好回饋。不要猶豫，勇敢去推進吧，這會是個順利又成功的開始！","actions":[{"title":"主動出擊","desc":"今天就聯繫KOL，約好時間把產品送過去，你的積極會得到好回應。"},{"title":"準備周全","desc":"在送產品前，把所有資料都準備好，讓KOL感受到你的用心和專業。"},{"title":"尋求建議","desc":"如果過程中有疑問，可以請教公司裡有經驗的同事，他們會很樂意幫你。"}],"warnings":"今天整體運勢很不錯，但還是要提醒你，在溝通時保持耐心，避免因為急於求成而忽略細節。多聽聽對方的想法，這樣事情會更圓滿順利。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時候你的能量最旺，做事效率高。"},{"name":"巳時","time":"09:00-11:00","reason":"火土能量強，有利於溝通與推進。"},{"name":"午時","time":"11:00-13:00","reason":"火土能量持續旺盛，是行動的好時機。"}],"oracle":"今日貴人相助，事半功倍，勇敢邁出一步，收穫超出預期。"}', '{"dayPillar":"癸未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"辰","tenGod":"正印","overallScore":5,"tarotCard":"教皇","tarotKeywords":["傳統","智慧","指引"],"moonPhase":"下弦月","moonLunarDay":22,"dominantElement":"火","weakestElement":"金","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-10', 5, '"2026-03-10T04:00:22.000Z"'),
(360003, 8280171, 'love', '愛情感情', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，今天對你的感情來說，是個不錯的日子，可以好好把握。因為今天流日是癸未日，這個「癸水」對你這個戊土日主來說，就像是滋潤你的雨水，能讓你的感情更柔軟、更流動。這代表你今天在感情上會比較有耐心，也更容易感受到對方的心意，或是讓對方感受到你的溫暖。塔羅牌的「戰車」也說了，只要你堅定心意，勇敢表達，感情上會有突破和進展。別想太多，勇敢去愛就對了，你會發現今天的心情特別好，也特別有魅力，去創造屬於你的美好吧！","actions":[{"title":"主動關心","desc":"今天適合主動給心儀對象或伴侶發個訊息，問候一下，讓對方感受到你的溫暖和體貼。"},{"title":"真誠溝通","desc":"有什麼心裡話，今天可以試著跟對方好好聊聊，你會發現溝通起來特別順暢，誤會也容易解開。"},{"title":"製造浪漫","desc":"為感情生活加點料，可以準備個小驚喜，或是安排一頓浪漫晚餐，讓感情升溫。"}],"warnings":"今天雖然感情運不錯，但也要注意別太過於沉浸在自己的世界裡，有時候會忽略了對方的感受。另外，下弦月提醒你要多反思，別急著做重大承諾，先感受一下彼此的心意再說。","bestHours":[{"name":"子時","time":"23:00-01:00","reason":"這時候心境平靜，適合思考感情。"},{"name":"申時","time":"15:00-17:00","reason":"這個時段能量好，適合約會或告白。"},{"name":"酉時","time":"17:00-19:00","reason":"感情交流順暢，適合與伴侶互動。"}],"oracle":"心之所向，素履以往。堅定你的愛，幸福自會來。"}', '{"dayPillar":"癸未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"辰","tenGod":"正財","overallScore":6,"tarotCard":"戰車","tarotKeywords":["勝利","意志","前進"],"moonPhase":"下弦月","moonLunarDay":22,"dominantElement":"火","weakestElement":"水","favorableElements":["金","水"],"unfavorableElements":["土","火"],"dayMasterStem":"戊","dayMasterElement":"土"}', '2026-03-10', 6, '"2026-03-10T05:00:01.000Z"'),
(360004, 8280171, 'love', '愛情感情', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"老弟，今天你在感情上會感覺比較踏實，是個適合好好經營關係的日子。因為今天這個「癸未」日，對你這個像大地一樣的戊土日主來說，代表著穩定的財富和踏實感。這種能量會讓你對感情的付出更實際，也更容易感受到對方給你的溫暖。別想太多花俏的，把重心放在真心交流和實際行動上，你會發現感情會自然而然地開花結果。好好把握，你會感覺被愛包圍的！","actions":[{"title":"真心交流","desc":"今天適合跟另一半或心儀對象好好聊聊，說說心裡話，讓對方感受到你的真誠，感情會更穩固。"},{"title":"實際付出","desc":"與其說甜言蜜語，不如為對方做點實際的事情，比如幫忙分擔家務，或準備一份小禮物，更能打動人心。"},{"title":"規劃未來","desc":"如果你有伴侶，可以一起規劃一些未來的目標，像是旅行、儲蓄，這會讓你們的關係更緊密，更有方向感。"}],"warnings":"今天雖然感情運不錯，但要注意別因為過於實際而忽略了浪漫情趣，偶爾也要來點小驚喜。另外，因為今天火的能量比較強，情緒上可能會有一點點急躁，記得保持耐心，避免因為小事而產生不必要的摩擦。","bestHours":[{"name":"子時","time":"23:00-01:00","reason":"這時候思緒清晰，適合深度交流。"},{"name":"申時","time":"15:00-17:00","reason":"心情平穩，適合輕鬆約會。"},{"name":"酉時","time":"17:00-19:00","reason":"感情能量旺盛，表達愛意的好時機。"}],"oracle":"真心付出，收穫必豐。愛是耕耘，更是收成。"}', '{"dayPillar":"癸未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"巳","tenGod":"正財","overallScore":6,"tarotCard":"戰車","tarotKeywords":["勝利","意志","前進"],"moonPhase":"下弦月","moonLunarDay":22,"dominantElement":"火","weakestElement":"水","favorableElements":["金","水"],"unfavorableElements":["土","火"],"dayMasterStem":"戊","dayMasterElement":"土"}', '2026-03-10', 6, '"2026-03-10T05:00:52.000Z"'),
(390001, 8280171, 'love', '愛情感情', '跟現在男朋友能走下去嗎', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，你今天問跟男朋友能不能走下去，這問題問得好！今天對你來說，是個適合穩紮穩打的日子。因為今天流日是癸未日，對你這個戊土日主來說，就像是遇到了一筆穩定的收入，感情上也是一樣，不是那種轟轟烈烈的激情，而是細水長流的累積。這時候，多去觀察和感受彼此之間是不是有那種踏實的連結，而不是急著要一個結果。只要你用心經營，關係是能往好的方向發展的，別擔心，你值得被好好愛著！","actions":[{"title":"深度溝通","desc":"找個時間跟男朋友好好聊聊，聽聽他心裡真實的想法，也把你自己的感受說出來，別藏著。"},{"title":"共同規劃","desc":"一起討論一下未來的計畫，哪怕是小小的週末旅行，也能讓你們的關係更穩固、更有方向感。"},{"title":"展現支持","desc":"多給男朋友一些鼓勵和支持，讓他感覺到你是他堅實的後盾，這會讓你們感情升溫。"}],"warnings":"今天雖然適合穩健發展，但也要注意別太過於鑽牛角尖，或是因為一些小事就想太多。感情需要耐心，但也要保持輕鬆的心情，別讓壓力影響了你們的相處。","bestHours":[{"name":"子時","time":"23:00-01:00","reason":"這個時段思緒清晰，適合心靈交流。"},{"name":"申時","time":"15:00-17:00","reason":"能量流動順暢，適合輕鬆約會。"},{"name":"酉時","time":"17:00-19:00","reason":"情感交流的好時機，說出心裡話。"}],"oracle":"用心灌溉的感情，終將開出美麗的花朵，穩穩地走下去吧！"}', '{"dayPillar":"癸未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"酉","tenGod":"正財","overallScore":6,"tarotCard":"戰車","tarotKeywords":["勝利","意志","前進"],"moonPhase":"下弦月","moonLunarDay":22,"dominantElement":"火","weakestElement":"水","favorableElements":["金","水"],"unfavorableElements":["土","火"],"dayMasterStem":"戊","dayMasterElement":"土"}', '2026-03-10', 6, '"2026-03-10T13:49:39.000Z"'),
(420001, 1, 'work', '工作事業', '明天我要到新竹出差會開車載同事，回程的時候要載他去機場之後再把東西和器材載回公司，這一段過程請你幫我分析看看有什麼需要注意的嗎？', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"老弟，你明天這趟新竹出差加載送任務，聽起來有點複雜，但別擔心，今天的天象對你來說是個不錯的時機。因為你本身就像棵大樹（甲木），今天又遇到跟你一樣的大樹（比肩），這表示你做事會特別有幹勁，獨立完成任務的能力很強。所以，這趟行程你完全可以自己掌握，把事情處理得妥妥貼貼。只要你心裡有譜，照著計畫走，這趟任務會很順利，甚至能展現出你的領導力。相信自己，你行的！","actions":[{"title":"事前規劃好路線","desc":"出發前把新竹到機場、機場回公司的路線都先查好，尤其注意路況和時間，避免臨時手忙腳亂。"},{"title":"保持清晰溝通","desc":"跟同事確認好上下車時間、地點，以及機場送機的細節，讓大家都清楚，避免誤會和延誤。"},{"title":"主動承擔責任","desc":"既然要載送器材，就主動確認好數量和狀況，確保安全運送，展現你可靠的一面。"}],"warnings":"今天雖然你很有衝勁，但要稍微注意一下，因為環境中木的能量比較強，可能會讓你有點固執己見，或是跟人意見不合。開車時也要特別專心，避免因為急躁而忽略一些小細節。還有，今天土的能量最弱，可能在處理一些實際的、瑣碎的事情上需要多點耐心。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時候木火能量旺，適合出發，做事順暢。"},{"name":"巳時","time":"09:00-11:00","reason":"火土能量增強，有利於溝通與執行，事情推進順利。"},{"name":"午時","time":"11:00-13:00","reason":"火的能量最旺，能讓你思路清晰，處理事情更有效率。"}],"oracle":"今日你如勁松獨立，穩健前行，每一步都踏實有力，事事皆能成。"}', '{"dayPillar":"甲申","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"丑","tenGod":"比肩","overallScore":5,"tarotCard":"戀人","tarotKeywords":["選擇","愛情","和諧"],"moonPhase":"下弦月","moonLunarDay":23,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-11', 5, '"2026-03-10T21:27:40.000Z"'),
(420002, 1, 'work', '工作事業', '今天的穿搭你怎麼建議？', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，今天你問穿搭，這可是個好問題！因為你今天特別適合展現獨立和自信，所以穿搭上也要能襯托出你的氣場。今天日子的能量，就像有另一個你站在旁邊給你力量，同時也提醒你要有自己的主見。穿得精神、俐落，能讓你今天在工作上更有衝勁，也能讓大家看到你積極的一面。別忘了，穿搭也是一種無聲的表達，今天就讓它替你說話，展現你的專業和果斷吧！","actions":[{"title":"穿搭建議","desc":"選擇大地色系或沉穩的顏色，像是咖啡、米白、深藍，這些顏色能讓你看起來更穩重可靠，也符合今天需要沉澱的能量。"},{"title":"材質挑選","desc":"選擇質感好、剪裁俐落的衣物，例如棉麻或羊毛材質，能提升你的專業形象，也讓你在職場上更有說服力。"},{"title":"配件點綴","desc":"可以佩戴一些小巧精緻的飾品，例如手錶或簡約的項鍊，這些能為你的整體造型加分，展現你的品味。"}],"warnings":"今天雖然適合獨立行動，但也要注意不要太過強勢，以免在溝通上產生不必要的摩擦。穿搭上避免過於鮮豔或浮誇的顏色，保持專業和內斂會更好，這樣更能讓你的工作順利推進。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時候穿搭最有靈感，能讓你一天都充滿活力。"},{"name":"巳時","time":"09:00-11:00","reason":"這個時段的選擇能讓你工作效率高，展現專業。"},{"name":"午時","time":"11:00-13:00","reason":"此時穿搭能助你人際和諧，溝通順暢。"}],"oracle":"穿出你的態度，展現你的光芒，今天你就是職場上最亮眼的存在！"}', '{"dayPillar":"甲申","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"辰","tenGod":"比肩","overallScore":5,"tarotCard":"戀人","tarotKeywords":["選擇","愛情","和諧"],"moonPhase":"下弦月","moonLunarDay":23,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-11', 5, '"2026-03-11T03:56:52.000Z"'),
(420003, 1, 'work', '工作事業', '今天的穿搭你怎麼建議？以今天五行能量的分配，和我的命格來看的話', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，今天你問穿搭，這可是個好問題！今天對你這個屬木的人來說，是個展現自我、充滿競爭力的一天。因為今天的天象，就像有另一棵跟你一樣的大樹在你身邊，讓你特別想衝、想獨立。在穿搭上，既然今天木的能量很強，但你又需要火和土來幫你，所以穿一些能代表火和土的顏色，像是紅色、橘色、黃色或大地色系，就能讓你更穩、更有力量。這樣不只讓你看起來精神飽滿，也能幫你把今天的能量用得更好。放心去展現你自己吧，你很棒！","actions":[{"title":"穿搭選色","desc":"今天可以多穿紅色、橘色系的衣服，或是帶點黃色、咖啡色等大地色系，這些顏色能給你帶來好運和穩定感。"},{"title":"配件點綴","desc":"如果衣服顏色不方便換，可以選個紅色的手錶、黃色的包包，或是土色系的鞋子，小地方也能加分。"},{"title":"保持自信","desc":"穿搭只是輔助，最重要的是你內心的自信。今天你充滿力量，大膽去表達自己，你會發現很多機會。"}],"warnings":"今天雖然你很有衝勁，但因為木的能量很強，容易跟人有點小摩擦。穿搭上避免全身都是綠色或藍色，那樣會讓木的能量太旺，反而容易衝動。記得溫和一點，多聽聽別人的意見，會讓事情更順利。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"此時段你能量最旺，適合思考重要決策。"},{"name":"巳時","time":"09:00-11:00","reason":"火的能量開始上升，有助於你展現才華。"},{"name":"午時","time":"11:00-13:00","reason":"火的能量最強，是行動和溝通的最佳時機。"}],"oracle":"今日展現自我，色彩助你穩健前行，你的光芒，無人能擋！"}', '{"dayPillar":"甲申","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"辰","tenGod":"比肩","overallScore":5,"tarotCard":"戀人","tarotKeywords":["選擇","愛情","和諧"],"moonPhase":"下弦月","moonLunarDay":23,"dominantElement":"木","weakestElement":"土","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-11', 5, '"2026-03-11T03:58:24.000Z"'),
(420004, 8280171, 'love', '愛情感情', '跟現在的男朋友能結婚嗎', '{"fortuneIndex":70,"fortuneLabel":"吉","coreReading":"兄弟，你問能不能跟現在的男朋友結婚，這問題問得好！從今天的能量來看，你今天會感覺到一些壓力，好像有些事情需要你去面對和處理。這就像感情路上總會遇到一些考驗，但別怕，這不是說不能結，而是提醒你，現在是個好好思考、沉澱的時機。今天會有貴人出現，他們會給你一些不錯的建議，幫助你把這些壓力變成動力，讓你們的感情更穩固。好好把握這些機會，你會發現，這些挑戰反而會讓你們更靠近。相信自己，也相信你們的感情，一切都會好的！","actions":[{"title":"坦誠溝通","desc":"今天適合跟男朋友好好聊聊，把心裡的想法、對未來的期待都說出來，別憋著。真誠的交流能化解很多問題。"},{"title":"尋求建議","desc":"身邊如果有長輩或比較有經驗的朋友，可以找他們聊聊，聽聽他們的看法。他們可能會給你一些意想不到的啟發。"},{"title":"共同規劃","desc":"可以和男朋友一起規劃一些小目標，比如一次旅行、一個共同的興趣。這能讓你們看到彼此的未來，增進默契。"}],"warnings":"今天在感情上可能會感覺有些壓力或不確定感，這時候別急著下決定，也別因為一點小事就鑽牛角尖。多給自己和對方一些空間，用耐心和溫柔去處理，避免因為一時的情緒而說出傷人的話。","bestHours":[{"name":"申時","time":"15:00-17:00","reason":"這時候你的能量最旺，思考清晰，適合溝通。"},{"name":"酉時","time":"17:00-19:00","reason":"貴人運強，可能會有好的建議出現。"},{"name":"子時","time":"23:00-01:00","reason":"心境平靜，適合反思和沉澱。"}],"oracle":"真心相待，耐心耕耘，愛的力量將引領你走向幸福。"}', '{"dayPillar":"甲申","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"酉","tenGod":"七殺","overallScore":6,"tarotCard":"力量","tarotKeywords":["勇氣","耐心","內在力量"],"moonPhase":"下弦月","moonLunarDay":23,"dominantElement":"火","weakestElement":"水","favorableElements":["金","水"],"unfavorableElements":["土","火"],"dayMasterStem":"戊","dayMasterElement":"土"}', '2026-03-11', 6, '"2026-03-11T14:40:26.000Z"'),
(450001, 540175, 'work', '工作事業', NULL, '{"fortuneIndex":70,"fortuneLabel":"吉","coreReading":"老弟，今天在工作上，你內心那股想衝破框架、展現自己獨特想法的能量特別強。這就像你心裡有個聲音在說：「別再墨守成規了，是時候做點不一樣的！」因為今天的能量很適合你發揮創意、提出新點子，或是用新的方法解決問題。這股能量能幫你打開新的局面，但同時也要記得，說話表達時要多一份體諒，別因為太過直接而傷到別人。勇敢去闖，但也要細心顧及人際關係，這樣才能走得更穩更遠，加油！","actions":[{"title":"大膽創新","desc":"今天是你展現獨特見解的好時機，別害怕提出跟別人不一樣的想法，你的創意可能會帶來突破性的進展。"},{"title":"溝通技巧","desc":"在表達意見時，試著多點耐心和同理心。雖然你想法很棒，但溫和的語氣能讓你的建議更容易被接受。"},{"title":"整理思緒","desc":"雖然今天適合衝，但也要留點時間給自己靜下來，好好整理一下手邊的資料或規劃，為下一步做準備。"}],"warnings":"今天在工作上，要特別注意你的言辭，別因為太過直接或急於表達而無意間得罪了同事或上司。雖然你是為公事好，但也要顧及人家的感受，避免不必要的摩擦。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時候腦袋最清晰，適合思考新方案。"},{"name":"未時","time":"13:00-15:00","reason":"下午衝勁足，適合推進重要事項。"},{"name":"巳時","time":"09:00-11:00","reason":"能量充沛，適合處理複雜任務。"}],"oracle":"創新火花點燃今日，堅定前行，勝利在望，無畏展現你的光芒。"}', '{"dayPillar":"乙酉","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"午","tenGod":"傷官","overallScore":5,"tarotCard":"戰車","tarotKeywords":["勝利","意志","前進"],"moonPhase":"殘月","moonLunarDay":24,"dominantElement":"火","weakestElement":"土","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-12', 5, '"2026-03-12T08:17:23.000Z"'),
(450002, 540175, 'work', '工作事業', '最近有想要轉職的念頭，請問依照我現在的流年或流月，適合留在現在公司還是依照我自己的想法找一個比較能長久待的公司呢？', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，你現在有想轉職的念頭，這很正常，因為今天這個日子，你內心那股想要突破、想要創新的能量特別強。對你這個壬水日主來說，今天就像是你的想法特別多，特別想把一些舊的東西打破，去創造新的可能。所以，你會有想換個環境、找個更適合自己長久發展的地方，這完全是順應這股能量。現在是個好時機去探索新的機會，但記得要保持冷靜，別太衝動。相信自己的直覺，你一定能找到更好的路！","actions":[{"title":"積極尋找機會","desc":"今天你腦袋裡的想法特別多，很適合去看看有哪些職位或公司吸引你，多方打聽，不要設限。"},{"title":"展現獨特想法","desc":"如果你有面試機會，大膽說出你的創新點子，展現你不同於他人的地方，這會是你的加分項。"},{"title":"整理作品履歷","desc":"趁著這股想突破的勁兒，好好整理一下你的履歷和作品集，讓它們更亮眼，準備好迎接新挑戰。"}],"warnings":"今天雖然想法很多，但說話時要稍微注意一下，別因為太想表達自己的觀點，不小心得罪了人。另外，現在是殘月，做重大決定前多給自己一點時間思考，別急著下定論，先觀望一下會比較好。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時段思緒清晰，適合規劃。"},{"name":"巳時","time":"09:00-11:00","reason":"這時段行動力強，適合執行。"},{"name":"未時","time":"13:00-15:00","reason":"這時段人緣不錯，適合溝通。"}],"oracle":"內心渴望突破，此刻正是揚帆起航時，勇敢追尋，未來值得期待！"}', '{"dayPillar":"乙酉","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"午","tenGod":"傷官","overallScore":5,"tarotCard":"戰車","tarotKeywords":["勝利","意志","前進"],"moonPhase":"殘月","moonLunarDay":24,"dominantElement":"火","weakestElement":"土","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-12', 5, '"2026-03-12T08:17:36.000Z"'),
(450003, 540175, 'work', '工作事業', '其實我有面試一間，覺得跟主管算合得來，不過我現在卡著離職的時間 加上我也想多看看公司，我要答應這間公司呢？還是繼續找？', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，今天對你來說，是個突破的好日子！你日主是壬水，今天乙酉日，這股能量會讓你特別想衝破現狀，去展現你的才能。你說面試那間公司，感覺跟主管合得來，這其實是個好兆頭，因為你的直覺在告訴你，那裡可能適合你發揮。今天這股力量很強，會讓你覺得不該被舊規則綁住。所以，如果你心裡已經有點傾向那間公司，別猶豫太久，這時候的你很有力量去爭取你想要的。相信自己的判斷，勇敢往前走就對了！","actions":[{"title":"勇敢爭取條件","desc":"既然感覺不錯，可以試著和對方談談離職時間的彈性，或是其他你關心的條件，今天你很有機會爭取到好結果。"},{"title":"展現獨特想法","desc":"在與新公司溝通時，大膽提出你的創新思維或解決方案，讓他們看到你的價值，這會讓他們更想留下你。"},{"title":"評估內心渴望","desc":"靜下心來問問自己，這間公司是不是你真正想要的？如果答案是肯定的，就別讓其他顧慮困住你，勇敢做決定。"}],"warnings":"今天雖然適合突破，但也要小心說話太直接，不小心得罪人。尤其在跟現有公司談離職時，話要說得圓融一點，別讓自己陷入不必要的麻煩。保持冷靜，別讓情緒主導一切。","bestHours":[{"name":"辰時","time":"07:00-09:00","reason":"這時段思緒清晰，適合做重要決定。"},{"name":"未時","time":"13:00-15:00","reason":"這時段溝通順暢，適合談判和交流。"},{"name":"巳時","time":"09:00-11:00","reason":"這時段能量充沛，適合積極行動。"}],"oracle":"心之所向，素履以往。今日你內心渴望，便是前行方向。"}', '{"dayPillar":"乙酉","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"午","tenGod":"傷官","overallScore":5,"tarotCard":"戰車","tarotKeywords":["勝利","意志","前進"],"moonPhase":"殘月","moonLunarDay":24,"dominantElement":"火","weakestElement":"土","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-12', 5, '"2026-03-12T08:25:03.000Z"'),
(480001, 1, 'work', '工作事業', '以我的命格來說，我之前開的印刷店，姓名學老師為什麼會取名為「京宸印刷」，你分析看看', '{"fortuneIndex":85,"fortuneLabel":"大吉","coreReading":"兄弟，你問這個名字「京宸印刷」是怎麼來的，其實從我們現在掌握的命格和今天的運勢來看，很難直接說出姓名學老師當初是怎麼想的。因為姓名學有它自己一套的學問，跟我們看你今天的運勢不太一樣。但我想說的是，你日主是甲木，就像一棵大樹，而「京宸」這個名字聽起來就很大氣、有格局，就像要承載很多東西一樣。今天你運勢特別好，火的能量很旺，這對你來說是展現才華、把想法變成實際成果的好時機。所以，不管名字當初怎麼取的，重要的是你現在怎麼去經營它，把你的才華和熱情投入進去，那才是真正讓事業發光發熱的關鍵。相信自己，你的印刷店一定會越來越好！","actions":[{"title":"大膽展現才華","desc":"今天火的能量很足，是你的「食神」當令。多去跟客戶溝通你的創意，或是把印刷品的設計理念說出來，讓大家看到你的用心和專業。"},{"title":"主動創造機會","desc":"不要被動等待訂單，可以主動去開發新客戶，或是提出一些創新的印刷方案。你的熱情和點子今天特別容易被看見和接受。"},{"title":"整理工作環境","desc":"殘月的時候，很適合整理和沉澱。把印刷店裡裡外外整理一下，讓空間更清爽，也讓心情更開闊，為接下來的衝刺做好準備。"}],"warnings":"今天雖然運勢很旺，但也要注意別因為太過興奮而忽略了細節。特別是跟客戶溝通時，多一份耐心，把話說清楚，避免因為小誤會影響了合作。另外，殘月也提醒你，有些事情可以先規劃，但不要急著一次到位，給自己一點喘息的空間。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"適合靜心思考，規劃創意。"},{"name":"申時","time":"15:00-17:00","reason":"溝通交流順暢，適合提案。"},{"name":"戌時","time":"19:00-21:00","reason":"靈感湧現，適合總結和創作。"}],"oracle":"你的才華是點亮京宸的火光，勇敢表達，讓世界看見你的光芒！"}', '{"dayPillar":"丙戌","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"未","tenGod":"食神","overallScore":8,"tarotCard":"力量","tarotKeywords":["勇氣","耐心","內在力量"],"moonPhase":"殘月","moonLunarDay":25,"dominantElement":"火","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-13', 8, '"2026-03-13T09:44:04.000Z"'),
(510001, 540175, 'work', '工作事業', '我應該選最初的工作，還是繼續找工作？', '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"兄弟，今天這個日子對你來說，是個講規矩、走正道的日子。因為今天的能量特別適合處理正式事務，像是面試、簽約這些。你問該選最初的工作還是繼續找，我會說，今天這股能量很支持你把事情定下來，特別是那些需要你展現專業、負責任的工作。如果你手上的這個機會是個正規、穩當的選擇，今天去談判或接受，會比較順利。別想太多，相信自己的判斷，今天就是你把事情搞定的好時機！","actions":[{"title":"評估現有工作","desc":"仔細思考你手上的這個工作機會，是不是符合你對穩定和發展的期待，別急著拒絕。"},{"title":"積極溝通","desc":"如果你對現有工作有疑問，今天很適合和對方好好聊聊，把條件談清楚。"},{"title":"展現專業","desc":"無論是接受還是繼續找，今天都要展現你負責任、專業的一面，給人好印象。"}],"warnings":"今天雖然適合把事情定下來，但因為你本命最弱的是金，而今天環境五行水也少，可能在決策上會有點猶豫不決。記得多聽聽內心的聲音，別被外部的資訊搞亂了方向，保持冷靜和客觀。殘月也提醒你，現在是沉澱和準備的時期，不適合衝動行事。","bestHours":[{"name":"申時","time":"15:00-17:00","reason":"這段時間能量最旺，做事效率高。"},{"name":"酉時","time":"17:00-19:00","reason":"這段時間能量最旺，適合收尾定案。"},{"name":"未時","time":"13:00-15:00","reason":"這段時間能量旺盛，有利於推進事務。"}],"oracle":"今日正官入局，公正之光照亮前路，你的選擇將迎來穩固的基石。"}', '{"dayPillar":"己丑","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"未","tenGod":"正官","overallScore":6,"tarotCard":"正義","tarotKeywords":["公正","真相","平衡"],"moonPhase":"殘月","moonLunarDay":28,"dominantElement":"火","weakestElement":"水","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-16', 6, '"2026-03-16T10:39:35.000Z"'),
(510002, 540175, 'work', '工作事業', '請你根據我的流月來看，我幾月離職好？', '{"fortuneIndex":70,"fortuneLabel":"吉","coreReading":"老弟，你問幾月離職好，但今天給你的資訊是看『今天』的運勢，沒有提供『流月』的資料，所以沒辦法直接告訴你哪個月離職最好。不過，從今天的運勢來看，今天很適合處理那些需要規矩、講求正式的事情，像是和上司溝通、簽約這類的。如果你今天有什麼離職的想法，可以先好好整理一下思緒，把該準備的資料都弄好，跟主管好好談，今天會比較順利。別急，一步一步來，你會找到最好的時機的！","actions":[{"title":"整理離職計畫","desc":"把離職的理由、交接事項都想清楚，今天很適合做這種有條理的規劃。"},{"title":"與主管溝通","desc":"如果你已經有離職想法，今天適合和上司進行正式且有建設性的對話。"},{"title":"審閱合約文件","desc":"若有任何離職相關文件或新工作合約需要簽署，今天仔細檢查會很順利。"}],"warnings":"今天雖然適合處理正式事務，但你的本命五行水很旺，而今天環境中水元素卻是零，這表示你可能會感覺有點孤單或不被理解。在溝通時，多點耐心，別太衝動，好好表達自己的想法，會減少摩擦。","bestHours":[{"name":"申時","time":"15:00-17:00","reason":"這段時間你的能量最旺，做事效率高。"},{"name":"酉時","time":"17:00-19:00","reason":"這段時間你的能量最旺，有利於決策。"},{"name":"未時","time":"13:00-15:00","reason":"這段時間你的能量最旺，適合推進事務。"}],"oracle":"心之所向，行之所往，每一步都算數，勇敢前行，天命護佑。"}', '{"dayPillar":"己丑","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"未","tenGod":"正官","overallScore":6,"tarotCard":"正義","tarotKeywords":["公正","真相","平衡"],"moonPhase":"殘月","moonLunarDay":28,"dominantElement":"火","weakestElement":"水","favorableElements":["水","金"],"unfavorableElements":["木","火"],"dayMasterStem":"壬","dayMasterElement":"水"}', '2026-03-16', 6, '"2026-03-16T10:40:54.000Z"'),
(540001, 690036, 'health', '健康身心', NULL, '{"fortuneIndex":75,"fortuneLabel":"吉","coreReading":"老弟啊，今天你在健康身心這塊，整體來說是個不錯的日子！你看，今天這個辛卯日對你這個甲木日主來說，就像是給了你一個清晰的框架和規矩，讓你做事情更有條理。這種規律感，對你的身心健康特別有幫助。加上今天有教皇牌的指引，代表你心裡渴望找到一個方向，或者想讓自己更穩定。新月也來了，正是重新設定目標的好時機。所以，今天很適合好好規劃一下自己的生活作息，讓身心都歸位，你會感覺特別踏實。別忘了，你一直都是很棒的，今天就好好把握這個機會，讓自己更上一層樓！","actions":[{"title":"規劃作息","desc":"今天特別適合把你的日常作息時間表拿出來，好好規劃一下，像是幾點睡、幾點起、什麼時候運動，讓生活更有規律。"},{"title":"尋求建議","desc":"如果你在健康或心靈方面有什麼困惑，今天很適合找個你信任的前輩或專業人士聊聊，聽聽他們的經驗和建議。"},{"title":"靜心冥想","desc":"找個安靜的角落，花個15-30分鐘，閉上眼睛，深呼吸，讓自己完全放鬆下來，清理思緒，感受內心的平靜。"}],"warnings":"今天雖然整體不錯，但要注意你的身體裡火的能量比較弱，可能會感覺手腳有點涼，或者精神上容易疲憊。記得多喝溫水，吃些溫熱的食物，別讓自己太累，適時休息很重要。尤其現在水也比較弱，要多補充水分，別讓身體缺水了。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時候靜心養神，對身心恢復特別好。"},{"name":"申時","time":"15:00-17:00","reason":"適合小憩或做些放鬆活動，補充體力。"},{"name":"戌時","time":"19:00-21:00","reason":"適合整理思緒，為明天做好準備，心靈平靜。"}],"oracle":"今日規律作息，心靈自得清明，定能穩健前行，成就美好！"}', '{"dayPillar":"辛卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"午","tenGod":"正官","overallScore":4,"tarotCard":"教皇","tarotKeywords":["傳統","智慧","指引"],"moonPhase":"新月（朔）","moonLunarDay":30,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-18', 4, '"2026-03-18T08:50:21.000Z"'),
(540002, 690036, 'health', '健康身心', '今天失眠為何', '{"fortuneIndex":65,"fortuneLabel":"吉","coreReading":"老弟，你今天會覺得失眠，可能是因為今天整體環境的能量比較偏向「規範和秩序」，讓你心裡有點繃緊，不太容易放鬆。加上你本身是甲木，就像一棵大樹，今天環境中「木」的能量也特別強，就像周圍都是旺盛的樹木，雖然有助你發揮，但也容易讓你腦袋停不下來。這種情況下，身體會有點亢奮，自然就比較難入睡。別擔心，這不是什麼大問題，只是能量流動的影響，好好調整一下就好，明天又是新的一天！","actions":[{"title":"睡前放鬆","desc":"睡前一小時放下手機，做些輕柔的伸展或聽點輕音樂，讓身心慢慢沉靜下來。"},{"title":"泡腳助眠","desc":"用溫熱的水泡泡腳，可以幫助你放鬆緊繃的神經，促進血液循環，更容易入睡。"},{"title":"規劃明天","desc":"把明天要做的事情簡單列出來，讓腦袋不再胡思亂想，心裡踏實了自然好睡。"}],"warnings":"今天因為環境能量比較強，你可能會覺得腦袋轉個不停，不容易靜下來。晚上睡前盡量避免刺激性的活動或思考太多複雜的事情，給自己一個緩衝時間，讓身心能慢慢放鬆下來，才不會影響睡眠品質喔。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時候能量平穩，適合深度休息。"},{"name":"戌時","time":"19:00-21:00","reason":"心境容易平靜，準備入睡的好時機。"},{"name":"申時","time":"15:00-17:00","reason":"適合小憩片刻，補充能量。"}],"oracle":"心靜如水，萬事皆安。放鬆身心，好夢自然來。"}', '{"dayPillar":"辛卯","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"午","tenGod":"正官","overallScore":4,"tarotCard":"教皇","tarotKeywords":["傳統","智慧","指引"],"moonPhase":"新月（朔）","moonLunarDay":30,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-18', 4, '"2026-03-18T08:50:54.000Z"'),
(570001, 1, 'health', '健康身心', NULL, '{"fortuneIndex":55,"fortuneLabel":"小吉","coreReading":"老弟，今天在健康身心這塊，你這棵甲木大樹會感覺到一股力量在拉扯，有點像樹枝被風吹得搖晃。因為今天的天象對你來說，就像是身邊競爭的人多了點，可能會讓你心裡覺得有點累，精神上容易消耗。所以今天別太逞強，尤其是身體上，該休息就休息，別硬撐。塔羅牌的星星牌出來，說明你內心其實充滿希望，這份希望就是你最好的療癒力量。把注意力放在你真正想做的事情上，讓心靈得到滋養，你會感覺好很多的。記住，放鬆和照顧好自己，比什麼都重要。","actions":[{"title":"多休息","desc":"今天身體容易感到疲憊，不管多忙，都要找時間小憩片刻，讓身體和精神都喘口氣，別硬撐。"},{"title":"多喝水","desc":"今天環境中水元素比較弱，多補充水分能幫助你維持身體機能，讓循環更好，精神也會更清爽。"},{"title":"靜心放鬆","desc":"找個安靜的地方，聽聽輕音樂或冥想幾分鐘，讓心靈沉澱下來，減少內耗，你會感覺更平靜。"}],"warnings":"今天要注意別讓自己太過勞累，身體的疲憊感可能會比平時明顯。同時，情緒上容易因為一些小事感到煩躁，記得深呼吸，別讓小情緒影響了你的好心情。保持平常心，對健康最有幫助。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時候能量較旺，適合深度休息或沉澱。"},{"name":"巳時","time":"09:00-11:00","reason":"這段時間火土能量足，適合活動筋骨，曬曬太陽。"},{"name":"戌時","time":"19:00-21:00","reason":"適合放鬆身心，準備休息，讓自己有個好睡眠。"}],"oracle":"靜心養神，蓄力待發，你的光芒終會閃耀。"}', '{"dayPillar":"乙未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"酉","tenGod":"劫財","overallScore":4,"tarotCard":"星星","tarotCardNumber":17,"tarotKeywords":["希望","靈感","療癒"],"moonPhase":"眉月","moonLunarDay":4,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-22', 4, '"2026-03-22T14:04:46.000Z"'),
(570002, 1, 'health', '健康身心', NULL, '{"fortuneIndex":55,"fortuneLabel":"平","coreReading":"老弟啊，今天在健康身心這塊，你得特別留心點。因為你本身就像棵大樹（甲木），今天流日的力量（乙未）對你來說，有點像是遇到同伴來競爭資源，容易讓你感到消耗。身體上可能會覺得比較疲憊，精神上也容易因為一些小事感到煩躁。所以，今天最重要的就是放慢腳步，別給自己太大壓力。多給自己一點空間，好好照顧自己，別逞強，這樣才能穩穩地度過這一天。記住，你的健康最重要，別為了小事耗費太多精力。","actions":[{"title":"放鬆身心","desc":"今天容易感到心累，找個時間做些讓自己放鬆的事，比如聽音樂、泡澡，讓心情平靜下來。"},{"title":"溫和運動","desc":"避免劇烈運動，可以選擇散步、瑜伽或伸展，讓身體活動一下，但不要過度消耗體力。"},{"title":"好好吃飯","desc":"今天身體可能比較虛，多吃些溫和、好消化的食物，多補充水分，別讓自己餓著了。"}],"warnings":"今天因為流日的力量容易讓你感到疲憊和精神消耗，要特別注意情緒上的起伏，別因為小事跟人起爭執。身體上也要留意別過度勞累，尤其是手腳、筋骨這方面，小心扭傷或痠痛。多休息，別逞強。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時候身心比較平靜，適合好好休息，為一天儲備能量。"},{"name":"巳時","time":"09:00-11:00","reason":"這段時間精神會比較好，適合安排一些輕鬆的活動，讓身心舒暢。"},{"name":"戌時","time":"19:00-21:00","reason":"一天結束前，這時候適合放鬆，做些冥想或伸展，幫助睡眠。"}],"oracle":"靜心守己，能量回歸，你的光芒，終將閃耀。"}', '{"dayPillar":"乙未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"酉","tenGod":"劫財","overallScore":4,"tarotCard":"星星","tarotCardNumber":17,"tarotKeywords":["希望","靈感","療癒"],"moonPhase":"眉月","moonLunarDay":4,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-22', 4, '"2026-03-22T14:04:57.000Z"'),
(570003, 1, 'health', '健康身心', NULL, '{"fortuneIndex":65,"fortuneLabel":"小吉","coreReading":"老弟，今天在健康身心這塊，你得特別留意了。因為今天的天象對你這個像大樹一樣的甲木來說，有點像遇到強風，容易感到心神不寧，身體也可能覺得有點疲憊。特別是今天這個日子，對你來說是個「劫財」的日子，雖然主要說的是錢財，但精神上的消耗也算在內。所以，別讓那些無謂的競爭或煩心事耗掉你的精氣神。不過別擔心，塔羅牌的星星也說了，今天充滿希望，靈感會來，也是療癒身心的好時機。只要你主動去照顧好自己，就能把這些消耗轉化成滋養。記住，你的身心健康才是你最大的財富，好好愛自己，一切都會好起來的！","actions":[{"title":"放鬆心情","desc":"今天容易心煩，找個安靜的地方，聽聽輕音樂，或是做些讓自己心情平靜的事，別讓小事影響你。"},{"title":"補充能量","desc":"多吃些溫暖滋補的食物，像根莖類蔬菜、紅肉或堅果，幫身體補足元氣，別讓身體太累了。"},{"title":"適度運動","desc":"雖然容易累，但適度的散步或伸展，能幫助你放鬆緊繃的肌肉，讓氣血循環更好，精神也會提升。"}],"warnings":"今天你可能會覺得精神上有些消耗，容易感到疲憊或心神不寧。要小心別因為一些小事就鑽牛角尖，或是讓不必要的競爭影響到你的情緒。多給自己一點空間，別硬撐。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時候適合靜心休息，讓身心得到充分的恢復。"},{"name":"戌時","time":"19:00-21:00","reason":"這段時間是放鬆身心的好時機，可以準備睡覺或冥想。"},{"name":"巳時","time":"09:00-11:00","reason":"這時候精神狀態不錯，適合處理一些需要專注的事情。"}],"oracle":"靜心養神，你就是自己最好的避風港，別忘了，你的內在充滿力量！"}', '{"dayPillar":"乙未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"戌","tenGod":"劫財","overallScore":4,"tarotCard":"星星","tarotCardNumber":17,"tarotKeywords":["希望","靈感","療癒"],"moonPhase":"眉月","moonLunarDay":4,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-22', 4, '"2026-03-22T16:49:03.000Z"'),
(570004, 1, 'wealth', '財運金錢', NULL, '{"fortuneIndex":35,"fortuneLabel":"小凶","coreReading":"兄弟，今天在財運金錢這塊，你真的要多留心了。因為今天的日子對你來說，有點像是有朋友來跟你借錢，或者跟你搶生意，讓你感覺錢財容易流失。你本身就像一棵大樹，今天又遇到很多跟你一樣的樹來分食資源，所以錢財方面會比較吃緊。這時候不是衝鋒陷陣的好時機，而是要穩住陣腳，守好你現有的。別急，這只是一天的小考驗，撐過去就好，明天會更亮！","actions":[{"title":"保守理財","desc":"今天不適合做大筆投資或冒險的財務決定，最好把錢包看緊一點，避免不必要的開銷。"},{"title":"避免借貸","desc":"無論是借錢給別人還是自己借錢，今天都盡量避免，容易產生麻煩或損失，能免則免。"},{"title":"檢查帳務","desc":"趁今天把自己的帳單、收支好好整理一下，看看有沒有漏洞，提早發現問題就能解決。"}],"warnings":"今天在金錢上容易有意外的支出，或者感覺錢財流動不順暢。跟人合作或合夥的時候，也要特別留意細節，避免因為誤會或競爭而造成損失，保持低調會比較好。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時段能量較為穩定，適合靜心思考財務規劃。"},{"name":"巳時","time":"09:00-11:00","reason":"這個時段的氣場對你來說比較有利，處理事情會順一些。"},{"name":"戌時","time":"19:00-21:00","reason":"夜晚時分，適合整理思緒，為明天的財運做準備。"}],"oracle":"穩紮穩打，守住現有，星星指引方向，希望就在前方。"}', '{"dayPillar":"乙未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"亥","tenGod":"劫財","overallScore":4,"tarotCard":"星星","tarotCardNumber":17,"tarotKeywords":["希望","靈感","療癒"],"moonPhase":"眉月","moonLunarDay":4,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-22', 4, '"2026-03-22T17:39:37.000Z"'),
(570005, 1, 'wealth', '財運金錢', NULL, '{"fortuneIndex":45,"fortuneLabel":"平","coreReading":"老弟啊，今天你的財運金錢方面，確實需要多留心一點。因為今天整體環境對你來說，有點像是在跟別人搶東西，或者說，容易把錢花在不該花的地方。你本身就像棵大樹，今天風有點大，容易搖晃。所以，今天在金錢上，保守一點、穩一點，別急著做大決定，守住現有的就好。不過別擔心，今天也有像星星一樣的希望和靈感，讓你能在困境中找到新的方向。記住，這只是暫時的，穩住就好，明天會更好！","actions":[{"title":"保守理財","desc":"今天在投資或大筆消費上要特別謹慎，避免衝動行事，能不花錢就先不花，守住荷包最重要。"},{"title":"避免借貸","desc":"不論是借錢給別人還是向別人借錢，今天都不是個好時機，容易有去無回或產生糾紛。"},{"title":"整理帳務","desc":"趁今天把自己的收支明細好好整理一下，了解錢的去向，為未來的理財打下基礎。"}],"warnings":"今天在金錢方面要特別注意，可能會遇到一些讓你破財的狀況，比如不必要的開銷，或是跟朋友合夥時意見不合導致損失。保持低調，少出風頭，就能避開不少麻煩。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這段時間你的思緒會比較清晰，適合規劃。"},{"name":"巳時","time":"09:00-11:00","reason":"這段時間能量較好，有利於處理事務。"},{"name":"戌時","time":"19:00-21:00","reason":"這段時間心境平穩，適合反思和總結。"}],"oracle":"穩住腳步，靜待時機。你的內在力量，會引導你走向豐盛。"}', '{"dayPillar":"乙未","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"亥","tenGod":"劫財","overallScore":4,"tarotCard":"星星","tarotCardNumber":17,"tarotKeywords":["希望","靈感","療癒"],"moonPhase":"眉月","moonLunarDay":4,"dominantElement":"木","weakestElement":"水","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"甲","dayMasterElement":"木"}', '2026-03-22', 4, '"2026-03-22T18:21:24.000Z"'),
(570006, 9423663, 'work', '工作事業', NULL, '{"fortuneIndex":85,"fortuneLabel":"大吉","coreReading":"兄弟，今天對你的工作事業來說，真是個大好日子！你本身是乙木，今天流日丙申，這股力量會讓你特別有想法，腦子裡會冒出很多創新的點子。就像你內心那股不甘平凡的勁兒被點燃了，很適合去打破一些舊規矩，嘗試新的做法。加上今天太陽高照，整個人充滿活力，自信滿滿，做什麼都容易成功。別怕，放手去幹，今天就是你展現才華的好時機，你會被看見的！","actions":[{"title":"大膽創新","desc":"今天是你展現獨特想法的好機會。別藏著，把那些新點子、新方案勇敢地提出來，會得到不錯的回應。"},{"title":"積極溝通","desc":"多跟同事、上司交流你的看法，特別是那些你覺得可以改進的地方。你的見解會給團隊帶來新氣象。"},{"title":"展現活力","desc":"保持積極樂觀的態度，把你的熱情感染給身邊的人。你的活力會讓你成為團隊的亮點，工作也會更順利。"}],"warnings":"今天雖然充滿能量，但有時候說話可能會比較直接，不經意間容易得罪人。記得在表達意見的時候，多花點心思，讓話語更圓潤一些，避免不必要的摩擦，這樣你的創新才能更好地被接受。","bestHours":[{"name":"丑時","time":"01:00-03:00","reason":"這時候思緒特別清晰，適合規劃或沉澱想法。"},{"name":"申時","time":"15:00-17:00","reason":"這段時間你的行動力最強，適合推進重要事項。"},{"name":"戌時","time":"19:00-21:00","reason":"這時候人際互動特別好，適合溝通協調或社交。"}],"oracle":"今日火光照亮前路，創新之風助你高飛，勇敢展現，成功在望！"}', '{"dayPillar":"丙申","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"丑","tenGod":"傷官","overallScore":7,"tarotCard":"太陽","tarotCardNumber":19,"tarotKeywords":["成功","喜悅","活力"],"moonPhase":"眉月","moonLunarDay":5,"dominantElement":"火","weakestElement":"土","favorableElements":["火","土"],"unfavorableElements":["木","水"],"dayMasterStem":"乙","dayMasterElement":"木"}', '2026-03-23', 7, '"2026-03-22T22:28:55.000Z"'),
(570007, 8280171, 'love', '愛情感情', NULL, '{"fortuneIndex":65,"fortuneLabel":"吉","coreReading":"老弟，今天你在感情上會感覺自己特別有主見，也很有自己的想法。因為今天這個日子對你來說，就像有另一個你站在旁邊，讓你更想展現自己，也更獨立。這種感覺會讓你對感情有更明確的態度。如果遇到喜歡的人，你會更敢表達心意；如果感情中有什麼不順心，你也會更堅定地去面對。但記得，有主見是好事，可別太固執，多聽聽對方怎麼說，感情才會更順利。相信自己，也相信愛的力量，今天會是個不錯的開始！","actions":[{"title":"勇敢表達","desc":"今天你特別有自信，遇到喜歡的對象，就大方說出你的感受，別藏著掖著，機會是自己創造的。"},{"title":"獨立思考","desc":"感情上有什麼決定，今天很適合自己想清楚。別急著找人商量，先聽聽自己內心的聲音。"},{"title":"展現魅力","desc":"多參加一些社交活動，展現你獨立自信的一面。你的光芒會吸引到欣賞你的人，好好把握。"}],"warnings":"今天雖然你很有自己的想法，但也要注意別太過強勢，或是只顧著自己。有時候，太堅持己見可能會讓對方覺得有點壓力，或是造成不必要的摩擦。記得給對方留點空間，多點耐心去溝通。","bestHours":[{"name":"子時","time":"23:00-01:00","reason":"這時候你的能量特別旺盛，有利於思考和規劃感情。"},{"name":"申時","time":"15:00-17:00","reason":"這個時段有利於溝通交流，適合和心儀對象互動。"},{"name":"酉時","time":"17:00-19:00","reason":"是展現個人魅力、提升好感度的時機，好好把握。"}],"oracle":"心之所向，素履以往。今日獨立，愛亦隨行。"}', '{"dayPillar":"戊戌","monthPillar":"辛卯","yearPillar":"丙午","hourBranch":"戌","tenGod":"比肩","overallScore":4,"tarotCard":"愚者（22）","tarotCardNumber":22,"tarotKeywords":["大智若愚","圆滿归零","超越智慧"],"moonPhase":"上弦月","moonLunarDay":7,"dominantElement":"火","weakestElement":"水","favorableElements":["金","水"],"unfavorableElements":["土","火"],"dayMasterStem":"戊","dayMasterElement":"土"}', '2026-03-25', 4, '"2026-03-25T16:43:56.000Z"');

