-- Data for experts (2 rows)
INSERT INTO `experts` (`id`, `userId`, `publicName`, `title`, `bio`, `profileImageUrl`, `coverImageUrl`, `tags`, `status`, `paymentQrUrl`, `ratingAvg`, `ratingCount`, `createdAt`, `updatedAt`, `specialties`, `languages`, `consultationModes`, `socialLinks`, `priceMin`, `priceMax`, `slug`, `bioHtml`, `sectionTitle`) VALUES
(1, 3330308, '星座撲克牌占卜', '通靈.占卜40年', '結善緣，了因果', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663104688923/MLF7bLVZzzxdGTPVXTct3c/expert-images/1-profile-1772882412150.jpeg', NULL, '[]', 'active', NULL, '0.00', 0, '"2026-03-04T07:25:36.000Z"', '"2026-03-10T04:54:46.000Z"', '["前世今生","占星","靈魂解讀"]', '中文', '["video","voice","text","in_person"]', NULL, 500, 3000, NULL, '', NULL),
(2, 1, 'Wiliiam', '解語師', '來「蒔境解語」，不用緊張、也不用假裝
就當作是來找一個懂你的朋友，喝杯茶，把心裡的話，好好地說一次
在這裡陪你一起，看懂自己
不聊遙遠的命運，也不講深奧的大道理。
我們就用你的生日，這組專屬於你的數字，來看看你的「使用說明書」上寫了些什麼——你的天賦、你的矛盾，還有你常常自己都沒發現的閃光點', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663104688923/MLF7bLVZzzxdGTPVXTct3c/expert-images/2-profile-1772839976353.jpeg', 'https://d2xsxph8kpxj0f.cloudfront.net/310519663104688923/MLF7bLVZzzxdGTPVXTct3c/expert-images/2-cover-1772840026238.jpeg', '[]', 'active', NULL, '0.00', 0, '"2026-03-04T07:31:44.000Z"', '"2026-03-07T23:49:12.000Z"', '["靈魂解讀","數字命理","塔羅牌"]', '中文', '["video","voice","text","in_person"]', NULL, 500, 3000, 'william', '<h2>來「蒔境解語」，看懂自己</h2>
<p>
  我是 William。在這裡，不用緊張，也不用假裝。  

  就當作是來找一個懂你的朋友，喝杯茶，把心裡的話，好好地說一次。
</p>
<p>
  我不聊遙遠的命運，也不講深奧的大道理。我們只專注於你，以及兩種看懂自己的方式：
</p>

<hr>

<h3>📖 你的「人生使用說明書」</h3>
<p>
  <strong>透過【數字命理】深度解讀</strong>  

  我們會用你的生日，這組專屬於你的數字，來看看說明書上寫了些什麼——你的天賦、你的矛盾，還有你常常自己都沒發現的閃光點。
</p>

<h3>🎴 當下的「十字路口指引」</h3>
<p>
  <strong>透過【塔羅牌】映照當下</strong>  

  當你對某個具體問題感到困惑時，塔羅牌就像一面鏡子，能清晰地照出你內心的真實狀態、眼前的選擇，以及最適合你的下一步。
</p>', NULL);

-- Data for feature_plans (7 rows)
INSERT INTO `feature_plans` (`id`, `moduleId`, `name`, `description`, `points3Days`, `points7Days`, `points15Days`, `points30Days`, `shopUrl`, `allowPointsRedemption`, `allowPurchase`, `isActive`, `sortOrder`, `createdAt`, `updatedAt`) VALUES
('bazi_decadal_annual', 'module_luck_cycle', '大限流年', '洞察未來十年的運勢起伏，規劃人生的每一步關鍵棋。

「大限流年深度解析」是天命共振系統最核心的專業級功能。它將為您揭示：

- **大限分析 (每十年)：** 您目前及未來所處的十年大運吉凶，看清事業、財運、感情的宏觀趨勢，助您順勢而為，避開逆境。
- **流年分析 (每一年)：** 精準解析當前年份的運程細節，預知該年的機遇與挑戰，告訴您今年應該衝刺還是沉潛。

此功能為「專業版」會員專享，是您進行長期生涯規劃、重大決策時不可或缺的最高級別命理參謀。', 1000, 1800, 2900, 5000, NULL, 1, 1, 1, 0, '"2026-03-04T12:49:58.000Z"', '"2026-03-04T12:49:58.000Z"'),
('dietary_compass', 'module_diet', '飲食羅盤', '五行開運食譜・你的專屬飲食羅盤
 這是在前端直接呈現給用戶的商品名稱，設計上融合了三個層次：
「五行開運」： 直接點出核心理論與最終利益點（開運），吸引目標用戶。
「食譜」： 使用「食譜」而非「羅盤」，更貼近生活，讓用戶立刻明白這是關於「吃」的。
「你的專屬」： 強調功能的「個人化」屬性，與通用型的農民曆或食譜做出區隔。', 290, 490, 900, 1990, NULL, 1, 1, 1, 2, '"2026-03-04T12:33:45.000Z"', '"2026-03-04T12:35:56.000Z"'),
('divination_poe', 'module_oracle', '擲筊問卦', '心中有惑，難以抉擇？讓傳統的智慧為您指點迷津。

本功能提供一個高度擬真的線上擲筊體驗，您可以在靜心默念問題後，點擊按鈕進行擲筊。系統將根據「聖筊」、「笑筊」、「陰筊」的結果，給予對應的傳統解讀和現代化的行動建議。

每日提供免費體驗次數，讓您隨時隨地都能獲得一份來自東方的神秘指引。', 250, 480, 750, 1200, NULL, 1, 1, 1, 2, '"2026-03-03T21:19:39.000Z"', '"2026-03-03T21:25:24.000Z"'),
('lucky_number_lotto', 'module_lottery', '補運樂透', '別再盲目下注了！真正的幸運，來自與您自身能量的共振。

「補運樂透」功能，將深度解析您的八字命盤與當日的宇宙能量流動，推算出最能與您產生強烈共鳴的「天命靈數」。

這組數字不僅可用於樂透、彩券等場合，更能作為您當日的幸運指標，應用在選擇樓層、座位號碼、甚至是決策的參考上。立即解鎖，讓好運有跡可循！', 580, 990, 1650, 2500, NULL, 1, 1, 1, 1, '"2026-03-04T12:42:57.000Z"', '"2026-03-04T12:42:57.000Z"'),
('Metaphysics Calendar', 'module_calendar', '命理日曆', '靜態查閱工具，提供每日宜忌、吉時等信息。用戶黏性不如前兩者，但對深度用戶來說是重要的參考資料。', 200, 350, 590, 800, NULL, 1, 1, 1, 3, '"2026-03-03T21:25:16.000Z"', '"2026-03-03T21:25:16.000Z"'),
('Oracle Outfit', 'module_outfit', '神諭穿搭', '結合了個人化（八字五行）與實用性（每日穿搭建議），互動性強', 460, 750, 1200, 1950, NULL, 1, 1, 1, 1, '"2026-03-03T21:23:52.000Z"', '"2026-03-03T21:23:52.000Z"'),
('wealth_compass', 'module_wealth', '財運羅盤', '君子愛財，取之有道。真正的財富，來自於在對的時間，做對的決策。

「財運羅盤」是您的個人化財富策略儀表板。它不僅告訴您今日財運是吉是凶，更會結合您的本命財庫與流日能量，為您指明：

- **宜攻或宜守：** 今天適合積極投資、開拓業務，還是應該保守理財、靜觀其變？
- **財位方向：** 您的專屬旺財方位在哪裡？
- **求財建議：** 應該專注正財（本業），還是有機會獲得偏財（投資、意外之財）？

讓「財運羅盤」成為您每日決策的軍師，助您精準把握每一個財富的契機！', 260, 450, 700, 1200, NULL, 1, 1, 1, 3, '"2026-03-04T12:45:57.000Z"', '"2026-03-04T12:45:57.000Z"');

